import React, { useState, useMemo, useEffect } from 'react';
import { Maximize2, Minimize2, X, Filter } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';

interface ChartWrapperProps {
  title: string;
  allData: FinancialRecord[];
  children: (filteredData: FinancialRecord[], isExpanded: boolean) => React.ReactNode;
  availableMonths: string[];
  availableUGs: string[];
  isDarkMode: boolean;
  defaultGroup?: string; 
  defaultMonth?: string; // New prop to set initial month
  hideMonthFilter?: boolean; // New prop to hide month selector
  className?: string;
}

export const ChartWrapper: React.FC<ChartWrapperProps> = ({
  title,
  allData,
  children,
  availableMonths,
  availableUGs,
  isDarkMode,
  defaultGroup = 'ALL',
  defaultMonth = 'TODOS',
  hideMonthFilter = false,
  className = ''
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [localMonth, setLocalMonth] = useState<string>(defaultMonth);
  const [localUG, setLocalUG] = useState<string>('TODOS');
  const [localGroup, setLocalGroup] = useState<string>(defaultGroup);

  // Update local state if defaults change (e.g. data load or global filter change)
  useEffect(() => { setLocalMonth(defaultMonth); }, [defaultMonth]);
  useEffect(() => { setLocalGroup(defaultGroup); }, [defaultGroup]);

  // Filter logic specific to this card
  const filteredData = useMemo(() => {
    return allData.filter(item => {
      const matchGroup = localGroup === 'ALL' || item.group === localGroup;
      const matchMonth = localMonth === 'TODOS' || item.date === localMonth;
      const matchUG = localUG === 'TODOS' || item.ug === localUG;
      return matchGroup && matchMonth && matchUG;
    });
  }, [allData, localMonth, localUG, localGroup]);

  // Common Header Controls
  const Controls = () => (
    <div className="flex flex-wrap items-center gap-2 mt-2 sm:mt-0">
      {/* Group Filter (New) */}
      <div className="relative">
        <select
          value={localGroup}
          onChange={(e) => setLocalGroup(e.target.value)}
          className={`appearance-none pl-3 pr-8 py-1 rounded text-xs font-medium border outline-none cursor-pointer focus:ring-2 focus:ring-blue-500
            ${isDarkMode 
              ? 'bg-slate-900 border-slate-600 text-slate-300' 
              : 'bg-slate-50 border-slate-300 text-slate-700'
            }`}
        >
          <option value="ALL">Todos os Grupos</option>
          <option value={AccountGroup.BMP}>BMP</option>
          <option value={AccountGroup.CONSUMO}>CONSUMO</option>
          <option value={AccountGroup.INTANGIVEL}>INTANGÍVEL</option>
        </select>
        <Filter className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
      </div>

      {/* Month Filter - Conditionally Rendered */}
      {!hideMonthFilter && (
        <div className="relative">
          <select
            value={localMonth}
            onChange={(e) => setLocalMonth(e.target.value)}
            className={`appearance-none pl-3 pr-8 py-1 rounded text-xs font-medium border outline-none cursor-pointer focus:ring-2 focus:ring-blue-500
              ${isDarkMode 
                ? 'bg-slate-900 border-slate-600 text-slate-300' 
                : 'bg-slate-50 border-slate-300 text-slate-700'
              }`}
          >
            <option value="TODOS">Todos os Meses</option>
            {availableMonths.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
          <Filter className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
        </div>
      )}

      {/* UG Filter */}
      <div className="relative">
        <select
          value={localUG}
          onChange={(e) => setLocalUG(e.target.value)}
          className={`appearance-none pl-3 pr-8 py-1 rounded text-xs font-medium border outline-none cursor-pointer focus:ring-2 focus:ring-blue-500
             ${isDarkMode 
              ? 'bg-slate-900 border-slate-600 text-slate-300' 
              : 'bg-slate-50 border-slate-300 text-slate-700'
            }`}
        >
          <option value="TODOS">Todas as UGs</option>
          {availableUGs.map(ug => <option key={ug} value={ug}>{ug}</option>)}
        </select>
        <Filter className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-slate-400 pointer-events-none" />
      </div>

      {/* Expand/Collapse Button */}
      <button
        onClick={() => setIsExpanded(!isExpanded)}
        className={`p-1.5 rounded hover:bg-opacity-80 transition-colors
          ${isDarkMode ? 'hover:bg-slate-700 text-slate-400' : 'hover:bg-slate-200 text-slate-500'}
        `}
        title={isExpanded ? "Minimizar" : "Expandir"}
      >
        {isExpanded ? <Minimize2 className="w-4 h-4" /> : <Maximize2 className="w-4 h-4" />}
      </button>
    </div>
  );

  // Expanded View (Modal)
  if (isExpanded) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className={`w-full h-full max-w-7xl max-h-[90vh] rounded-xl shadow-2xl flex flex-col overflow-hidden
          ${isDarkMode ? 'bg-slate-800 border border-slate-700' : 'bg-white'}`}
        >
          {/* Modal Header */}
          <div className={`p-4 border-b flex items-center justify-between
            ${isDarkMode ? 'border-slate-700' : 'border-slate-200'}`}
          >
            <h2 className={`text-xl font-bold ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>
              {title}
            </h2>
            <div className="flex items-center gap-4">
              <Controls />
              <button 
                onClick={() => setIsExpanded(false)}
                className={`p-2 rounded-full hover:bg-red-500 hover:text-white transition-colors
                  ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}
                `}
              >
                <X className="w-6 h-6" />
              </button>
            </div>
          </div>

          {/* Modal Content */}
          <div className="flex-1 p-6 overflow-hidden flex flex-col">
            <div className="w-full h-full relative min-h-0 flex-1">
              {children(filteredData, isExpanded)}
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Default Card View
  return (
    <div className={`rounded-xl p-5 border shadow-sm flex flex-col overflow-hidden ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'} ${className}`}>
      <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-4 gap-2 flex-shrink-0">
        <h2 className={`text-lg font-semibold ${isDarkMode ? 'text-slate-200' : 'text-slate-800'}`}>
          {title}
        </h2>
        <Controls />
      </div>
      <div className="flex-1 relative min-h-0 w-full overflow-hidden">
        {children(filteredData, isExpanded)}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  LineChart, Line, TooltipProps, ComposedChart
} from 'recharts';
import { FinancialRecord } from '../types';
import { formatCurrency } from '../services/dataProcessor';
import { LayoutList, BarChart3 } from 'lucide-react';

interface ChartProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  isExpanded?: boolean;
}

// --- Custom Tooltip ---
const CustomDetailedTooltip = ({ active, payload, label, isDarkMode }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    // Values might come from different properties depending on the chart type
    // We prioritize the ones passed in payload or fallback to data attributes
    const diff = data.diff !== undefined ? data.diff : data.totalDiff;
    const siafi = data.siafi !== undefined ? data.siafi : data.totalSiafi;
    const siloms = data.siloms !== undefined ? data.siloms : data.totalSiloms;

    return (
      <div className={`min-w-[200px] p-4 rounded-xl border shadow-xl backdrop-blur-md z-50 ${isDarkMode ? 'bg-slate-900/95 border-slate-700 text-white' : 'bg-white/95 border-slate-200 text-slate-800'}`}>
        <p className="text-sm font-bold mb-3 pb-2 border-b border-slate-600/50">{label || data.ug}</p>
        <div className="space-y-2">
           <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 rounded-full bg-[#8b5cf6]"></div>
              <span className="text-xs font-medium opacity-80">Diferença:</span>
              <span className="text-sm font-bold font-mono ml-auto">{formatCurrency(diff)}</span>
           </div>
           <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 rounded-full bg-[#3b82f6]"></div>
              <span className="text-xs font-medium opacity-80">SIAFI:</span>
              <span className="text-sm font-bold font-mono ml-auto text-blue-400">{formatCurrency(siafi)}</span>
           </div>
           <div className="flex items-center gap-3">
              <div className="w-2.5 h-2.5 rounded-full bg-[#10b981]"></div>
              <span className="text-xs font-medium opacity-80">SILOMS:</span>
              <span className="text-sm font-bold font-mono ml-auto text-emerald-400">{formatCurrency(siloms)}</span>
           </div>
        </div>
      </div>
    );
  }
  return null;
};

// --- Comparison Bar Chart with Toggle ---
export const ComparisonChart: React.FC<ChartProps> = ({ data, isDarkMode, isExpanded }) => {
  const [viewMode, setViewMode] = useState<'composition' | 'ranking'>('composition');

  // Defensive check
  if (!data) return null;

  const aggregated = data.reduce((acc, curr) => {
    const found = acc.find(item => item.ug === curr.ug);
    if (found) {
      found.siafi += curr.siafiValue || 0;
      found.siloms += curr.silomsValue || 0;
      found.diff += curr.difference || 0;
      found.netDiff += (curr.silomsValue - curr.siafiValue); 
    } else {
      acc.push({ 
        ug: curr.ug, 
        siafi: curr.siafiValue || 0, 
        siloms: curr.silomsValue || 0, 
        diff: curr.difference || 0,
        netDiff: (curr.silomsValue - curr.siafiValue) || 0
      });
    }
    return acc;
  }, [] as { ug: string, siafi: number, siloms: number, diff: number, netDiff: number }[]);

  // Sort by Magnitude (Difference)
  aggregated.sort((a, b) => b.diff - a.diff);

  const totalNetDivergence = aggregated.reduce((sum, item) => sum + item.netDiff, 0);

  // Decide how many items to show based on expansion and view mode
  const displayData = isExpanded ? aggregated : aggregated.slice(0, 15);

  if (displayData.length === 0) {
     return <div className="flex items-center justify-center h-full text-slate-500">Sem dados para exibir.</div>;
  }

  // Styles for scrolling logic
  const isHorizontal = viewMode === 'ranking';
  const containerStyle = isExpanded 
    ? (isHorizontal 
        ? { width: '100%', height: `${Math.max(600, displayData.length * 50)}px` } 
        : { width: `${Math.max(100, displayData.length * 70)}px`, height: '100%' }
      )
    : { width: '100%', height: '100%' };

  const overflowClass = isExpanded 
    ? (isHorizontal ? 'overflow-y-auto custom-scrollbar pr-2' : 'overflow-x-auto custom-scrollbar pb-2') 
    : '';

  return (
    <div className="flex flex-col h-full w-full relative">

      {/* View Toggle */}
      <div className="absolute top-0 right-10 sm:right-0 z-10 flex bg-slate-100 dark:bg-slate-700 rounded-lg p-0.5 border border-slate-200 dark:border-slate-600 shadow-sm">
        <button
          onClick={() => setViewMode('composition')}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-md transition-all
            ${viewMode === 'composition' 
              ? 'bg-white dark:bg-slate-600 text-slate-800 dark:text-white shadow-sm' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
            }`}
        >
          <BarChart3 className="w-3 h-3" />
          Composição
        </button>
        <button
          onClick={() => setViewMode('ranking')}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-md transition-all
            ${viewMode === 'ranking' 
              ? 'bg-white dark:bg-slate-600 text-slate-800 dark:text-white shadow-sm' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
            }`}
        >
          <LayoutList className="w-3 h-3" />
          Ranking
        </button>
      </div>

      {/* Expanded Only Metric */}
      {isExpanded && viewMode === 'composition' && (
        <div className={`mb-2 mr-36 px-3 py-2 rounded-lg border flex items-center justify-between max-w-md
           ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
           <span className="text-xs font-bold uppercase text-slate-400">
             Divergência Líquida
           </span>
           <span className={`text-sm font-mono font-bold
             ${totalNetDivergence > 0 ? 'text-emerald-500' : totalNetDivergence < 0 ? 'text-red-500' : 'text-slate-500'}
           `}>
             {totalNetDivergence > 0 ? '+' : ''}{formatCurrency(totalNetDivergence)}
           </span>
        </div>
      )}

      <div className={`flex-1 w-full min-h-0 mt-8 ${overflowClass}`}>
        <div style={containerStyle}>
          <ResponsiveContainer width="100%" height="100%">
            {viewMode === 'composition' ? (
              // COMPOSITION VIEW (Vertical Bars, Side-by-Side)
              <BarChart data={displayData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                <XAxis 
                  dataKey="ug" 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 11}} 
                  interval={0}
                  angle={isExpanded ? -45 : 0}
                  textAnchor={isExpanded ? 'end' : 'middle'}
                  height={isExpanded ? 60 : 30}
                  axisLine={false} 
                  tickLine={false} 
                />
                <YAxis 
                  tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
                  axisLine={false} 
                  tickLine={false}
                />
                <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} cursor={{fill: isDarkMode ? '#1e293b' : '#f1f5f9'}} />
                <Legend wrapperStyle={{ paddingTop: '10px' }} />
                <Bar dataKey="siafi" name="SIAFI" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                <Bar dataKey="siloms" name="SILOMS" fill="#10b981" radius={[4, 4, 0, 0]} />
              </BarChart>
            ) : (
              // RANKING VIEW (Horizontal Bars for better list view)
              <BarChart 
                data={displayData} 
                layout="vertical" 
                margin={{ top: 5, right: 30, left: 10, bottom: 5 }}
                barCategoryGap={isExpanded ? 10 : 20}
              >
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                <XAxis 
                  type="number"
                  tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
                  axisLine={false} 
                  tickLine={false}
                />
                <YAxis 
                  dataKey="ug" 
                  type="category" 
                  width={90}
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 11, fontWeight: 500}} 
                  axisLine={false} 
                  tickLine={false}
                />
                <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} cursor={{fill: isDarkMode ? '#1e293b' : '#f1f5f9', opacity: 0.5}} />
                {/* <Legend /> */}
                <Bar dataKey="diff" name="Diferença Absoluta" fill="#8b5cf6" radius={[0, 4, 4, 0]} barSize={isExpanded ? 20 : undefined} />
              </BarChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

// --- Evolution Line Chart ---

export const EvolutionChart: React.FC<ChartProps> = ({ data, isDarkMode }) => {
  if (!data) return null;

  const timeSeries = data.reduce((acc, curr) => {
    const found = acc.find(item => item.date === curr.date);
    if (found) {
      found.totalDiff += curr.difference;
      found.totalSiafi += curr.siafiValue;
      found.totalSiloms += curr.silomsValue;
    } else {
      acc.push({ 
        date: curr.date, 
        totalDiff: curr.difference, 
        totalSiafi: curr.siafiValue,
        totalSiloms: curr.silomsValue,
        timestamp: (curr.year * 100) + curr.monthIndex 
      });
    }
    return acc;
  }, [] as { date: string, totalDiff: number, totalSiafi: number, totalSiloms: number, timestamp: number }[]);

  timeSeries.sort((a, b) => a.timestamp - b.timestamp);

  if (timeSeries.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  return (
    <div className="w-full h-full min-h-[250px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={timeSeries} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
          <XAxis 
            dataKey="date" 
            tickFormatter={(val) => val.split('/')[0].substring(0,3)}
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false} 
          />
          <YAxis 
            tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false}
          />
          <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} />
          <Line 
            type="monotone" 
            dataKey="totalDiff" 
            name="Diferença Total" 
            stroke="#6366f1" 
            strokeWidth={3}
            dot={{ r: 4, fill: '#6366f1' }}
            activeDot={{ r: 6 }}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { normalizeData, formatCurrency, parseDateString, recalculateDeltas } from './services/dataProcessor';
import { parseExcelFile } from './services/excelParser';
import { AccountGroup, TimeFilter, FinancialRecord } from './types';
import { StatCard } from './components/StatCard';
import { ComparisonChart, EvolutionChart } from './components/Charts';
import { RankingList } from './components/RankingList';
import { TemporalHeatmap } from './components/TemporalHeatmap';
import { ChartWrapper } from './components/ChartWrapper';
import { FileUploadModal } from './components/FileUploadModal';
import { SiafiMessageModal } from './components/SiafiMessageModal';
import { CustomSelect } from './components/CustomSelect'; // Custom Component
import { 
  Activity, AlertTriangle, FileSpreadsheet, TrendingUp, Search, 
  LayoutDashboard, Layers, UploadCloud, Sun, Moon 
} from 'lucide-react';

function App() {
  // START EMPTY (No Mock Data)
  const [rawData, setRawData] = useState<any[]>([]);

  // UI State
  const [selectedGroup, setSelectedGroup] = useState<string>('ALL');
  const [timeFilter, setTimeFilter] = useState<TimeFilter>('MENSAL');
  const [selectedMonth, setSelectedMonth] = useState<string>('');
  const [selectedUG, setSelectedUG] = useState<string>('TODOS'); // New Global Filter
  const [searchTerm, setSearchTerm] = useState('');
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [hideZeros, setHideZeros] = useState(true);

  // Modals
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isMessageModalOpen, setIsMessageModalOpen] = useState(false);
  const [selectedRecordForMessage, setSelectedRecordForMessage] = useState<FinancialRecord | null>(null);

  // Effect: Enforce Dark Mode on Body
  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  // 1. PROCESS DATA: Normalize -> Recalculate Deltas
  const allData = useMemo(() => {
    const normalized = normalizeData(rawData);
    // Recalculate deltas based on whether we are looking Month-over-Month or Year-over-Year, etc.
    return recalculateDeltas(normalized, timeFilter);
  }, [rawData, timeFilter]);

  // 2. EXTRACT DROPDOWN LISTS
  const uniqueMonths = useMemo(() => {
    const dates = Array.from(new Set(allData.map(d => d.date))) as string[];
    return dates.sort((a, b) => parseDateString(a).timestamp - parseDateString(b).timestamp);
  }, [allData]);

  const uniqueUGs = useMemo(() => Array.from(new Set(allData.map(d => d.ug))).sort(), [allData]);

  // Auto-select latest month when data loads
  useEffect(() => {
    if (uniqueMonths.length > 0 && !selectedMonth) {
      setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    } else if (uniqueMonths.length > 0 && !uniqueMonths.includes(selectedMonth)) {
        // If current selection is invalid after new upload
        setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    }
  }, [uniqueMonths, selectedMonth]);

  // 3. FILTERING
  const filteredData = useMemo(() => {
    return allData.filter(item => {
      const matchSearch = item.ug.toLowerCase().includes(searchTerm.toLowerCase()) || item.cod.includes(searchTerm);
      const matchUG = selectedUG === 'TODOS' || item.ug === selectedUG;
      const matchZero = hideZeros ? item.difference !== 0 : true;
      // Note: Group filtering is handled at visual level for some components, or here for totals
      return matchSearch && matchZero && matchUG;
    });
  }, [allData, searchTerm, hideZeros, selectedUG]);

  // Subset: Current Month Only (For KPIs only)
  const currentMonthData = useMemo(() => {
    return filteredData.filter(item => 
        item.date === selectedMonth && 
        (selectedGroup === 'ALL' || item.group === selectedGroup)
    );
  }, [filteredData, selectedMonth, selectedGroup]);

  // Subset: Heatmap (Needs all months, ignores Global Group Filter for internal tabs)
  const heatmapData = useMemo(() => {
    return filteredData; // Contains all months, search applied, zeros hidden
  }, [filteredData]);

  // 4. KPI CALCULATIONS
  const stats = useMemo(() => {
    const totalDiff = currentMonthData.reduce((acc, curr) => acc + curr.difference, 0);
    const totalSiafi = currentMonthData.reduce((acc, curr) => acc + curr.siafiValue, 0);
    const totalSiloms = currentMonthData.reduce((acc, curr) => acc + curr.silomsValue, 0);
    const topOffender = currentMonthData.length > 0 
        ? currentMonthData.reduce((prev, current) => (prev.difference > current.difference) ? prev : current)
        : null;
    return { totalDiff, totalSiafi, totalSiloms, topOffender };
  }, [currentMonthData]);

  // Handlers
  const handleFileUpload = async (file: File) => {
    try {
      const parsed = await parseExcelFile(file);
      if (parsed.length > 0) {
        setRawData(parsed);
        alert(`Sucesso! ${parsed.length} linhas processadas.`);
      } else {
        alert("Arquivo vazio ou formato não reconhecido.");
      }
    } catch (e) {
      console.error(e);
      alert("Erro crítico ao processar arquivo. Verifique se é um Excel válido.");
    }
  };

  return (
    <div className={`min-h-screen pb-12 transition-colors duration-300 ${isDarkMode ? 'bg-[#020617] text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      <FileUploadModal 
        isOpen={isUploadModalOpen} 
        onClose={() => setIsUploadModalOpen(false)} 
        onUpload={handleFileUpload} 
      />

      <SiafiMessageModal 
        isOpen={isMessageModalOpen}
        onClose={() => setIsMessageModalOpen(false)}
        record={selectedRecordForMessage}
      />

      {/* STICKY TOP BAR - MAIN NAVIGATION */}
      <nav className={`${isDarkMode ? 'bg-[#0f172a]/95 border-slate-800' : 'bg-white/95 border-slate-200'} border-b sticky top-0 z-40 backdrop-blur-md`}>
        <div className="max-w-[1800px] mx-auto px-4 sm:px-6 h-16 flex items-center justify-between gap-4">

          <div className="flex items-center gap-3 min-w-max">
