    return (
      <div className={`min-w-[200px] p-4 rounded-xl border shadow-xl backdrop-blur-md z-50 ${isDarkMode ? 'bg-slate-900/95 border-slate-700 text-white' : 'bg-white/95 border-slate-200 text-slate-800'}`}>
