// --- Evolution Line Chart ---

export const EvolutionChart: React.FC<ChartProps> = ({ data, isDarkMode }) => {
  if (!data) return null;

  const timeSeries = data.reduce((acc, curr) => {
    const found = acc.find(item => item.date === curr.date);
    if (found) {
      found.totalDiff += curr.difference;
      found.totalSiafi += curr.siafiValue;
      found.totalSiloms += curr.silomsValue;
    } else {
      acc.push({ 
        date: curr.date, 
        totalDiff: curr.difference, 
        totalSiafi: curr.siafiValue,
        totalSiloms: curr.silomsValue,
        timestamp: (curr.year * 100) + curr.monthIndex 
      });
    }
    return acc;
  }, [] as { date: string, totalDiff: number, totalSiafi: number, totalSiloms: number, timestamp: number }[]);

  timeSeries.sort((a, b) => a.timestamp - b.timestamp);

  if (timeSeries.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  return (
    <div className="w-full h-full min-h-[250px]">
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={timeSeries} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
          <XAxis 
            dataKey="date" 
            tickFormatter={(val) => val.split('/')[0].substring(0,3)}
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false} 
          />
          <YAxis 
            tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false}
          />
          <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} />
          <Line 
            type="monotone" 
            dataKey="totalDiff" 
            name="Diferença Total" 
            stroke="#6366f1" 
            strokeWidth={3}
            dot={{ r: 4, fill: '#6366f1' }}
            activeDot={{ r: 6 }}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
import { LucideIcon } from 'lucide-react';

interface StatCardProps {
  title: string;
  value: string;
  subtitle?: string;
  icon: LucideIcon;
  colorClass: string; // expects something like "text-red-500"
  bgClass: string; // expects something like "bg-red-500"
}

export const StatCard: React.FC<StatCardProps> = ({ title, value, subtitle, icon: Icon, colorClass, bgClass }) => {
  // Helper to ensure Tailwind generates the dark mode classes by having full strings here
  // We map colors only for the ICON now. The TEXT value is forced to white in dark mode.
  const getThemeColors = (cls: string) => {
    if (cls.includes('red')) return { icon: 'dark:text-red-400' };
    if (cls.includes('blue')) return { icon: 'dark:text-blue-400' };
    if (cls.includes('emerald')) return { icon: 'dark:text-emerald-400' };
    if (cls.includes('amber')) return { icon: 'dark:text-amber-400' };
    return { icon: 'dark:text-slate-200' };
  };

  const themeColors = getThemeColors(colorClass);

  return (
    <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 p-6 flex items-start justify-between hover:shadow-md transition-all">
      <div>
        <p className="text-sm font-medium text-slate-500 dark:text-slate-400 mb-1">{title}</p>
        <h3 className="text-2xl font-bold text-slate-900 dark:text-white tracking-tight">{value}</h3>
        {subtitle && <p className="text-xs text-slate-400 dark:text-slate-500 mt-2">{subtitle}</p>}
      </div>
      <div className={`p-3 rounded-lg ${bgClass} bg-opacity-10 dark:bg-opacity-20`}>
        <Icon className={`w-6 h-6 ${colorClass} ${themeColors.icon}`} />
      </div>
    </div>
  );
};

