  const filteredData = useMemo(() => data.filter(item => 
    internalGroupFilter === 'ALL' || item.group === internalGroupFilter
  ), [data, internalGroupFilter]);

  // --- DYNAMIC COLOR LOGIC (10 LEVELS - LOCAL SCALING) ---
  // Now accepts localMax to scale colors relative to the specific UG's history
  const getCellColor = (value: number, localMax: number) => {
    if (value === 0) return 'bg-slate-800/40 text-slate-600 font-normal border border-slate-800/50';

    // Prevent division by zero
    const ratio = localMax > 0 ? value / localMax : 0;

    // Level 1: Lowest (0-10%) - Deepest Green
    if (ratio <= 0.10) return 'bg-emerald-950/80 text-emerald-400 font-normal border border-emerald-900/30';

    // Level 2: Very Low (10-20%) - Deep Green
    if (ratio <= 0.20) return 'bg-emerald-900/80 text-emerald-300 font-normal border border-emerald-800/30';

    // Level 3: Low (20-30%) - Medium Green
    if (ratio <= 0.30) return 'bg-emerald-800 text-emerald-100 font-medium border border-emerald-700/30';

    // Level 4: Low-Mid (30-40%) - Standard Green
    if (ratio <= 0.40) return 'bg-emerald-600 text-white font-medium border border-emerald-500/30';

    // Level 5: Mid (40-50%) - Lime Transition
    if (ratio <= 0.50) return 'bg-lime-600 text-white font-medium border border-lime-500/30';

    // Level 6: Mid-High (50-60%) - Yellow/Dark Yellow
    if (ratio <= 0.60) return 'bg-yellow-600 text-white font-bold border border-yellow-500/30 shadow-sm';

    // Level 7: High (60-70%) - Amber
    if (ratio <= 0.70) return 'bg-amber-500 text-white font-bold border border-amber-400/30 shadow-sm';

    // Level 8: Very High (70-80%) - Orange
    if (ratio <= 0.80) return 'bg-orange-500 text-white font-bold border border-orange-400/30 shadow-sm';

    // Level 9: Severe (80-90%) - Red
    if (ratio <= 0.90) return 'bg-red-500 text-white font-bold border border-red-400/30 shadow-md';

    // Level 10: Critical (90-100%) - Deep Red
    return 'bg-[#450a0a] text-red-100 font-black border border-red-500 shadow-[inset_0_0_8px_rgba(0,0,0,0.6)]'; 
  };

  // Compact Number Formatter (399.3M, 931k)
  const formatCompact = (val: number) => {
    if (val === 0) return '-';
    if (val >= 1000000) return `${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `${(val / 1000).toFixed(0)}k`;
    return val.toFixed(0);
  };

  // Group Badge Color Helper - MONOCHROME/NEUTRAL
  const getGroupBadgeClass = (group: string) => {
    // All groups use neutral colors now
    return 'bg-slate-700 text-slate-300';
  };

  // Sort logic: Total Difference across all visible months
  const sortedUGs = useMemo(() => {
    const ugs = Array.from(new Set(filteredData.map(d => d.ug))) as string[];
    return ugs.sort((a, b) => {
      const sumA = filteredData.filter(r => r.ug === a).reduce((acc, r) => acc + r.difference, 0);
      const sumB = filteredData.filter(r => r.ug === b).reduce((acc, r) => acc + r.difference, 0);
      return sumB - sumA;
    });
  }, [filteredData]);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden text-xs bg-[#0b1120] rounded-lg border border-slate-700">

      {/* Header Controls */}
      <div className="flex items-center justify-between gap-2 p-2 border-b border-slate-700 bg-slate-800">
        <div className="flex items-center gap-1 overflow-x-auto">
           {[
               { id: 'ALL', label: 'TODOS' },
               { id: AccountGroup.BMP, label: 'BMP' },
               { id: AccountGroup.CONSUMO, label: 'CONSUMO' },
               { id: AccountGroup.INTANGIVEL, label: 'INTANGIVEL' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setInternalGroupFilter(tab.id)}
                className={`px-3 py-1 rounded text-[10px] font-bold uppercase transition-all whitespace-nowrap
                  ${internalGroupFilter === tab.id 
                    ? 'bg-slate-600 text-white' 
                    : 'bg-slate-900 text-slate-400 hover:bg-slate-700 border border-slate-600'
                  }
                `}
              >
                {tab.label}
              </button>
            ))}
        </div>

        <div className="hidden sm:flex items-center gap-1 px-2 py-1 rounded bg-slate-900 border border-slate-700 text-slate-400 text-[10px] font-bold uppercase">
           <ArrowUpDown className="w-3 h-3" />
           Maior Valor
        </div>
      </div>

      {sortedUGs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-2">
            <span className="text-lg">Sem dados para exibir</span>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#0b1120] relative">
          <div className="w-full min-w-[700px] p-2">

            {/* 
               GRID LAYOUT DEFINITION 
               Col 1: 180px fixed (Name)
               Col 2: Auto-fit (Months) - minmax(0, 1fr) ensures equal distribution without overflow
               Col 3: 40px fixed (Action)
            */}
            <div 
              className="grid gap-1 mb-2 sticky top-0 z-10 bg-[#0b1120] pb-2 border-b border-slate-800 items-end"
              style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(0, 1fr)) 40px` }}
            >
                <div className="text-slate-500 font-bold uppercase tracking-wider pl-2 text-[10px]">UG / GRUPO</div>

                {availableMonths.map(month => (
                    <div key={month} className="text-center text-slate-500 font-bold uppercase text-[10px] truncate px-1">
                        {month.split('/')[0].substring(0, 3)}/{month.split('/')[1]?.substring(2,4)}
                    </div>
                ))}

                <div className="text-center text-slate-500 font-bold text-[10px]">MSG</div>
            </div>

            {/* Rows */}
            <div className="space-y-1">
              {sortedUGs.map(ug => {
                const ugRecords = filteredData.filter(d => d.ug === ug);
                const uniqueGroups = (Array.from(new Set(ugRecords.map(r => r.group))) as AccountGroup[]).sort();

                return uniqueGroups.map(group => {
                   // Calculate Local Max for this specific UG/Group combination across all loaded dates
                   const groupRecords = ugRecords.filter(r => r.group === group);
                   const localMax = groupRecords.length > 0 
                     ? Math.max(...groupRecords.map(r => r.difference)) 
                     : 1;

                   // Styles now depend on just being neutral
                   const groupClass = 'bg-slate-700 text-slate-300';
                   return (
                    <div 
                        key={`${ug}-${group}`} 
                        className="grid gap-1 items-center hover:bg-slate-800/30 rounded transition-colors"
                        style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(0, 1fr)) 40px` }}
                    >

                        {/* Name Column */}
                        <div className="flex items-center h-8 overflow-hidden rounded bg-slate-800/80 border border-slate-700/50">
                            <div className={`w-8 h-full flex items-center justify-center text-[8px] font-black uppercase ${groupClass}`}>
                                {group === AccountGroup.BMP ? 'BMP' : group === AccountGroup.CONSUMO ? 'CN' : 'INT'}
                            </div>
                            <div className="flex-1 px-2 text-slate-300 font-semibold truncate text-[10px]">
                                {ug}
                            </div>
                        </div>

                        {/* Months Data Cells */}
                        {availableMonths.map(month => {
                            const record = ugRecords.find(r => r.date === month && r.group === group);
                            const diff = record ? record.difference : 0;

                            return (
                                <div 
                                    key={month}
                                    className={`h-8 rounded flex items-center justify-center text-[10px] transition-all cursor-help border-transparent border
                                        ${getCellColor(diff, localMax)}
                                    `}
                                    title={record ? `${month}: R$ ${diff.toLocaleString('pt-BR')}` : 'Sem dados'}
                                >
                                    {formatCompact(diff)}
                                </div>
                            );
                        })}

                        {/* Action Column */}
                        <div className="flex justify-center h-8">
                             <button 
                                onClick={() => {
                                    const latest = ugRecords.filter(r => r.group === group).sort((a, b) => parseDateString(b.date).timestamp - parseDateString(a.date).timestamp)[0];
                                    if(latest) onSendMessage(latest);
                                }}
                                className="w-8 h-8 flex items-center justify-center rounded bg-slate-800 text-slate-500 hover:text-white hover:bg-blue-600 transition-colors border border-slate-700"
                             >
                                 <MessageSquareText className="w-3.5 h-3.5" />
                             </button>
                        </div>
                    </div>
                   );
                });
              })}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

export enum AccountGroup {
  CONSUMO = 'CONSUMO',
  BMP = 'BMP',
  INTANGIVEL = 'INTANGIVEL',
}

export type TimeFilter = 'MENSAL' | 'TRIMESTRAL' | 'SEMESTRAL' | 'ANUAL';

// Represents a single normalized record (one category per UG per date)
export interface FinancialRecord {
  id: string;
  date: string; // e.g., "JULHO/2025"
  monthIndex: number; // 0-11
  year: number;
  cod: string;
  ug: string;
  group: AccountGroup;
  siafiValue: number;
  silomsValue: number;
  difference: number;

  // For Evolution Analysis
  previousDifference?: number; // Difference in the previous period
  previousDate?: string; // The date of the record used for comparison
  delta?: number; // Current - Previous (Positive = Worsened/Increased Diff)

  // Analysis field: Which system is higher?
  preponderance: 'SIAFI' | 'SILOMS' | 'EQUAL';
}

// Represents the raw "wide" row from the Excel
export interface RawInputRow {
  data: string;
  cod: string;
  ug: string;
  // Group 1
  g1_name: string;
  g1_siafi: number;
  g1_siloms: number;
  g1_diff: number;
  // Group 2
  g2_name: string;
  g2_siafi: number;
  g2_siloms: number;
  g2_diff: number;
  // Group 3
  g3_name: string;
  g3_siafi: number;
  g3_siloms: number;
  g3_diff: number;
}

import { FinancialRecord, RawInputRow, AccountGroup, TimeFilter } from '../types';

// Helper to safely parse dates in format "MONTH/YEAR" or "Mon/Year"
export const parseDateString = (dateStr: string): { month: number, year: number, timestamp: number } => {
  try {
    if (!dateStr) return { month: 0, year: 0, timestamp: 0 };

    const parts = dateStr.split('/');
    if (parts.length < 2) return { month: 0, year: 0, timestamp: 0 };

    const [monthStr, yearStr] = parts;
    const months: Record<string, number> = {
      'JANEIRO': 0, 'FEVEREIRO': 1, 'MARÇO': 2, 'ABRIL': 3, 'MAIO': 4, 'JUNHO': 5,
      'JULHO': 6, 'AGOSTO': 7, 'SETEMBRO': 8, 'OUTUBRO': 9, 'NOVEMBRO': 10, 'DEZEMBRO': 11,
      'JAN': 0, 'FEV': 1, 'MAR': 2, 'ABR': 3, 'MAI': 4, 'JUN': 5,
      'JUL': 6, 'AGO': 7, 'SET': 8, 'OUT': 9, 'NOV': 10, 'DEZ': 11
    };

    const cleanMonth = monthStr.trim().toUpperCase();
    const month = months[cleanMonth] !== undefined ? months[cleanMonth] : 0;
    const year = parseInt(yearStr) || new Date().getFullYear();

    return {
      month,
      year,
      timestamp: new Date(year, month, 1).getTime()
    };
  } catch (e) {
    console.error("Date Parse Error", e);
    return { month: 0, year: 0, timestamp: 0 };
  }
};

// --- DATA NORMALIZATION ---
export const normalizeData = (rawRows: RawInputRow[]): FinancialRecord[] => {
  const normalized: FinancialRecord[] = [];
  if (!rawRows || !Array.isArray(rawRows)) return [];

  rawRows.forEach((row, index) => {
    // Defensive check
    if (!row) return;

    const { month, year } = parseDateString(row.data);
    const safeCod = row.cod || '000000';
    const safeUg = row.ug || 'DESCONHECIDO';

    // Helper to process a group safely
    const processGroup = (groupEnum: AccountGroup, siafi: number, siloms: number, explicitDiff: number) => {
      // Logic: Use explicit diff if present (and logically valid), else calc
      const finalDiff = explicitDiff !== 0 ? Math.abs(explicitDiff) : Math.abs(siafi - siloms);

      let preponderance: 'SIAFI' | 'SILOMS' | 'EQUAL' = 'EQUAL';
      if (siafi > siloms) preponderance = 'SIAFI';
      if (siloms > siafi) preponderance = 'SILOMS';

      // Unique ID Generator: SAFE against duplicates
      // ID = COD + GROUP + TIMESTAMP + INDEX (to ensure uniqueness if rows duplicate)
      const uniqueId = `${safeCod}-${groupEnum}-${year}${month}-${index}`;

      normalized.push({
        id: uniqueId,
        date: row.data,
        monthIndex: month,
        year: year,
        cod: safeCod,
        ug: safeUg,
        group: groupEnum,
        siafiValue: siafi || 0,
        silomsValue: siloms || 0,
        difference: finalDiff || 0,
        preponderance,
        // Init optional fields
        previousDifference: 0,
        previousDate: '',
        delta: 0
      });
    };

    // STRICT GROUP MAPPING
    processGroup(AccountGroup.CONSUMO, row.g1_siafi, row.g1_siloms, row.g1_diff);
    processGroup(AccountGroup.BMP, row.g2_siafi, row.g2_siloms, row.g2_diff);
    processGroup(AccountGroup.INTANGIVEL, row.g3_siafi, row.g3_siloms, row.g3_diff);
  });

  return normalized;
};

// --- DELTA RECALCULATION BASED ON TIME FILTER ---
export const recalculateDeltas = (data: FinancialRecord[], timeFilter: TimeFilter): FinancialRecord[] => {
  // 1. Determine the gap in months based on filter
  let monthGap = 1; // Default MENSAL
  if (timeFilter === 'TRIMESTRAL') monthGap = 3;
  if (timeFilter === 'SEMESTRAL') monthGap = 6;
  if (timeFilter === 'ANUAL') monthGap = 12;

  return data.map(record => {
    // Calculate target previous date
    let targetMonth = record.monthIndex - monthGap;
    let targetYear = record.year;

    // Handle year rollover (simple implementation for typical gaps)
    while (targetMonth < 0) {
      targetMonth += 12;
      targetYear -= 1;
    }

    // Find the comparison record (Previous period)
    // We match by COD and GROUP. UG Name is ignored as it might have typos in history.
    const prevRecord = data.find(r => 
      r.cod === record.cod && 
      r.group === record.group && 
      r.monthIndex === targetMonth && 
      r.year === targetYear
    );

    const prevDiff = prevRecord ? prevRecord.difference : 0;
    const prevDate = prevRecord ? prevRecord.date : (monthGap > 1 ? `PERÍODO ANTERIOR (-${monthGap}m)` : 'MÊS ANTERIOR');

    // Delta = Current - Previous
    // Positive Delta = Difference Increased (Worsened)
    // Negative Delta = Difference Decreased (Improved)
    const delta = record.difference - prevDiff;

    return {
      ...record,
      previousDifference: prevDiff,
      previousDate: prevDate,
      delta
    };
  });
};

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
    maximumFractionDigits: 2,
    minimumFractionDigits: 2
  }).format(value || 0);
};

// Helper for MMM/YY format (e.g., NOV/25)
const formatShortDate = (monthIndex: number, year: number) => {
  const monthNames = ["JAN", "FEV", "MAR", "ABR", "MAI", "JUN", "JUL", "AGO", "SET", "OUT", "NOV", "DEZ"];
  const m = monthNames[monthIndex] || "MES";
  const y = year.toString().slice(-2);
  return `${m}/${y}`;
};

// --- MESSAGE GENERATOR WITH CONDITIONAL LOGIC & ERROR HANDLING ---
export const generateSiafiMessageText = (record: FinancialRecord, msgNumber: string, deadline: string): string => {
  try {
    if (!record) throw new Error("Registro inválido para geração de mensagem.");

    const today = new Date();
    const dateStr = today.toLocaleDateString('pt-BR');
    const timeStr = today.toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'});

    const currentShortDate = record.date.toUpperCase(); // Use full date string from Excel
    const prevShortDate = record.previousDate ? record.previousDate.toUpperCase() : "PERÍODO ANTERIOR";

    // Determine Friendly Name for Group
    const groupMap: Record<string, string> = {
      [AccountGroup.CONSUMO]: "BENS DE CONSUMO",
      [AccountGroup.BMP]: "BENS MÓVEIS PERMANENTES",
      [AccountGroup.INTANGIVEL]: "BENS INTANGÍVEIS"
    };
    const groupText = groupMap[record.group] || "CONTA EM ANÁLISE";
    const groupTextLower = groupText.toLowerCase();

    const separator = "--------------------------------------------------";
    const deltaVal = record.delta || 0;
    const isWorsening = deltaVal > 0;

    // Header Subject
    const subjectAction = isWorsening ? "Incompatibilidade" : "Regularização";
    const msgCodeHeader = `${today.getFullYear()}/xxxxxxx ${subjectAction} de saldos nas contas de ${groupTextLower} - ${currentShortDate}`;

    // Body Logic
    let bodyParagraph = "";
    if (isWorsening) {
      bodyParagraph = `(Se PIORA): Conforme verificação realizada por esta Setorial na data de hoje, informo que essa UG está com divergência significativa (e crescente) de saldos entre os sistemas SIAFI e SILOMS nas contas de ${groupTextLower}, conforme os dados abaixo:`;
    } else {
      bodyParagraph = `(Se MELHORA): Conforme acompanhamento realizado por esta Setorial, identificou-se uma redução significativa na divergência de saldos entre os sistemas SIAFI e SILOMS nas contas de ${groupTextLower} no período analisado.`;
    }

    // Conclusion Logic
    let conclusionParagraph = "";
    if (isWorsening) {
      conclusionParagraph = `Diante do exposto, solicita-se ao gestor responsável que providencie a equalização das diferenças até o dia ${deadline || '[PRAZO]'}, considerando o fechamento mensal. Solicita-se, ainda, que seja encaminhada resposta via SAU, apresentando justificativa quanto às diferenças identificadas.`;
    } else {
      conclusionParagraph = `Esta Diretoria reconhece o trabalho realizado pela gestão da Unidade para a adequação e conformidade dos registros contábeis e patrimoniais. Solicitamos que as ações de regularização sejam mantidas para a eliminação completa das pendências remanescentes.`;
    }

    // Comparison Label
    const comparisonLabel = isWorsening ? "AUMENTO (PIORA)" : "REDUÇÃO (MELHORA)";
    const systemHigher = record.siafiValue > record.silomsValue ? "SIAFI" : "SILOMS";

    // --- TEMPLATE ASSEMBLY ---
    return `${msgCodeHeader}
Remetente: xxxxx - SETORIAL DE CONTABILIDADE
Enviado em: ${dateStr} às ${timeStr}
UG destinatárias: ${record.cod} ${record.ug}
Mensagem:

AG DA ADMINISTRAÇÃO: Ordenador de Despesas, Agente de Controle Interno, Gestor de Almoxarifado e demais gestores envolvidos.

MSG NR ${msgNumber || 'XXX'}/SUCONT-4/${today.toLocaleDateString('pt-BR').replace(/\//g, '')}.

${bodyParagraph}

${separator}
EVOLUÇÃO DA DIVERGÊNCIA
${separator}
PERÍODO ANTERIOR (${prevShortDate}):  ${formatCurrency(record.previousDifference || 0)}
PERÍODO ATUAL    (${currentShortDate}):  ${formatCurrency(record.difference)}
${separator}
${comparisonLabel}:    ${formatCurrency(Math.abs(deltaVal))}
SISTEMA MAIOR: ${systemHigher}
${separator}

${conclusionParagraph}

Por fim, coloco à disposição a Divisão de Acompanhamento Patrimonial para interações julgadas oportunas sobre este assunto.

DIREF/SUCONT/SUCONT-4
`;
  } catch (error) {
    console.error("Error generating message:", error);
    return "ERRO AO GERAR MENSAGEM. VERIFIQUE OS DADOS DO REGISTRO.";
  }
};

