function App() {
  // START EMPTY (No Mock Data)
  const [rawData, setRawData] = useState<any[]>([]);

  // UI State
  const [selectedGroup, setSelectedGroup] = useState<string>('ALL');
  const [timeFilter, setTimeFilter] = useState<TimeFilter>('MENSAL');
  const [selectedMonth, setSelectedMonth] = useState<string>('');
  const [selectedUG, setSelectedUG] = useState<string>('TODOS'); // New Global Filter
  const [searchTerm, setSearchTerm] = useState('');
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [hideZeros, setHideZeros] = useState(true);

  // Modals
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isMessageModalOpen, setIsMessageModalOpen] = useState(false);
  const [selectedRecordForMessage, setSelectedRecordForMessage] = useState<FinancialRecord | null>(null);

  // Effect: Enforce Dark Mode on Body
  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  // 1. PROCESS DATA: Normalize -> Recalculate Deltas
  const allData = useMemo(() => {
    const normalized = normalizeData(rawData);
    // Recalculate deltas based on whether we are looking Month-over-Month or Year-over-Year, etc.
    return recalculateDeltas(normalized, timeFilter);
  }, [rawData, timeFilter]);

  // 2. EXTRACT DROPDOWN LISTS
  const uniqueMonths = useMemo(() => {
    const dates = Array.from(new Set(allData.map(d => d.date))) as string[];
    return dates.sort((a, b) => parseDateString(a).timestamp - parseDateString(b).timestamp);
  }, [allData]);

  const uniqueUGs = useMemo(() => Array.from(new Set(allData.map(d => d.ug))).sort(), [allData]);

  // Auto-select latest month when data loads
  useEffect(() => {
    if (uniqueMonths.length > 0 && !selectedMonth) {
      setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    } else if (uniqueMonths.length > 0 && !uniqueMonths.includes(selectedMonth)) {
        // If current selection is invalid after new upload
        setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    }
  }, [uniqueMonths, selectedMonth]);

  // 3. FILTERING
  const filteredData = useMemo(() => {
    return allData.filter(item => {
      const matchSearch = item.ug.toLowerCase().includes(searchTerm.toLowerCase()) || item.cod.includes(searchTerm);
      const matchUG = selectedUG === 'TODOS' || item.ug === selectedUG;
      const matchZero = hideZeros ? item.difference !== 0 : true;
      // Note: Group filtering is handled at visual level for some components, or here for totals
      return matchSearch && matchZero && matchUG;
    });
  }, [allData, searchTerm, hideZeros, selectedUG]);

  // Subset: Current Month Only (For KPIs only)
  const currentMonthData = useMemo(() => {
    return filteredData.filter(item => 
        item.date === selectedMonth && 
        (selectedGroup === 'ALL' || item.group === selectedGroup)
    );
  }, [filteredData, selectedMonth, selectedGroup]);

  // Subset: Heatmap (Needs all months, ignores Global Group Filter for internal tabs)
  const heatmapData = useMemo(() => {
    return filteredData; // Contains all months, search applied, zeros hidden
  }, [filteredData]);

  // 4. KPI CALCULATIONS
  const stats = useMemo(() => {
    const totalDiff = currentMonthData.reduce((acc, curr) => acc + curr.difference, 0);
    const totalSiafi = currentMonthData.reduce((acc, curr) => acc + curr.siafiValue, 0);
    const totalSiloms = currentMonthData.reduce((acc, curr) => acc + curr.silomsValue, 0);
    const topOffender = currentMonthData.length > 0 
        ? currentMonthData.reduce((prev, current) => (prev.difference > current.difference) ? prev : current)
        : null;
    return { totalDiff, totalSiafi, totalSiloms, topOffender };
  }, [currentMonthData]);

  // Determine Comparison Label for Ranking
  const comparisonLabel = useMemo(() => {
     if (!selectedMonth || currentMonthData.length === 0) return `Comparando ${timeFilter}`;
     const sampleRecord = currentMonthData[0];
     const prevDate = sampleRecord.previousDate || 'N/A';
     // Extract short names e.g., JANEIRO/2025 -> JAN
     const currShort = selectedMonth.split('/')[0].substring(0,3);
     const prevShort = prevDate.includes('/') ? prevDate.split('/')[0].substring(0,3) : prevDate;

     return `Comparando ${currShort} contra ${prevShort}`;
  }, [currentMonthData, selectedMonth, timeFilter]);

  // Handlers
  const handleFileUpload = async (file: File) => {
    try {
      const parsed = await parseExcelFile(file);
      if (parsed.length > 0) {
        setRawData(parsed);
        alert(`Sucesso! ${parsed.length} linhas processadas.`);
      } else {
        alert("Arquivo vazio ou formato não reconhecido.");
      }
