interface RankingListProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  comparisonLabel?: string;
  onSendMessage?: (record: FinancialRecord) => void;
}

export const RankingList: React.FC<RankingListProps> = ({ data, isDarkMode, comparisonLabel, onSendMessage }) => {
  // Use defensive fallback for delta (?? 0)
  const worsened = data
    .filter(d => (d.delta ?? 0) > 100)
    .sort((a, b) => (b.delta ?? 0) - (a.delta ?? 0))
    .slice(0, 50);

  const improved = data
    .filter(d => (d.delta ?? 0) < -100)
    .sort((a, b) => (a.delta ?? 0) - (b.delta ?? 0))
    .slice(0, 50);

  // Updated to Monochrome/Neutral
  const getGroupBadgeColor = (group: string) => {
      // Neutral Slate styles for all groups
      return 'bg-slate-700 border-slate-600 text-slate-300';
  };

  const renderCard = (item: FinancialRecord, rank: number, type: 'worse' | 'better') => {
    const isWorse = type === 'worse';
    // Style logic: Red for worse, Emerald for better
    const cardBorder = isWorse ? 'border-red-500/30' : 'border-emerald-500/30';
    const cardBg = isWorse ? 'bg-red-500/5 hover:bg-red-500/10' : 'bg-emerald-500/5 hover:bg-emerald-500/10';
    const textColor = isWorse ? 'text-red-500' : 'text-emerald-500';

    return (
      <div 
        key={item.id} 
        className={`relative p-3 rounded-lg border ${cardBorder} ${cardBg} transition-all group mb-2`}
      >
        {/* Rank */}
        <div className={`absolute -left-1 top-3 w-6 h-6 flex items-center justify-center text-[10px] font-bold rounded-r shadow-sm
          ${isWorse ? 'bg-red-600 text-white' : 'bg-emerald-600 text-white'}`}>
          {rank}
        </div>

        <div className="pl-6 flex items-center justify-between gap-3">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2">
              <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded border uppercase ${getGroupBadgeColor(item.group)}`}>
                {item.group === AccountGroup.CONSUMO ? 'CONS' : item.group === AccountGroup.BMP ? 'BMP' : 'INT'}
              </span>
              <h4 className="font-bold text-sm truncate text-slate-200">{item.ug}</h4>
            </div>
            <div className="flex items-center gap-2 mt-1 text-[10px] text-slate-400">
               <span>{formatCurrency(item.previousDifference || 0)}</span>
               <ArrowRight className="w-3 h-3" />
               <span className="text-slate-300">{formatCurrency(item.difference)}</span>
            </div>
          </div>

          <div className="text-right">
             <div className={`text-sm font-bold ${textColor}`}>
               {isWorse ? '+' : ''}{formatCurrency(Math.abs(item.delta || 0))}
             </div>
          </div>

          {onSendMessage && (
            <button 
              onClick={(e) => { e.stopPropagation(); onSendMessage(item); }}
              className="p-1.5 rounded bg-slate-800 text-slate-400 hover:text-white hover:bg-slate-700 border border-slate-600 transition-colors"
            >
              <MessageSquareText className="w-4 h-4" />
            </button>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col lg:flex-row h-full w-full gap-4 overflow-hidden">
       {/* Worsened Column */}
       <div className="flex-1 flex flex-col overflow-hidden bg-slate-900/50 rounded-lg p-2 border border-slate-800">
          <div className="flex flex-col gap-1 mb-2 pb-2 border-b border-red-500/20">
             <div className="flex items-center gap-2">
                 <TrendingUp className="w-4 h-4 text-red-500" />
                 <h3 className="text-xs font-bold text-red-500 uppercase tracking-wider">Piora no Período</h3>
             </div>
             {comparisonLabel && (
                 <span className="text-[10px] text-slate-500 pl-6">{comparisonLabel}</span>
             )}
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar">
             {worsened.length === 0 ? <div className="text-center py-4 text-slate-600 text-xs">Sem registros.</div> : worsened.map((item, idx) => renderCard(item, idx + 1, 'worse'))}
          </div>
       </div>

       {/* Improved Column */}
       <div className="flex-1 flex flex-col overflow-hidden bg-slate-900/50 rounded-lg p-2 border border-slate-800">
          <div className="flex flex-col gap-1 mb-2 pb-2 border-b border-emerald-500/20">
             <div className="flex items-center gap-2">
                 <TrendingDown className="w-4 h-4 text-emerald-500" />
                 <h3 className="text-xs font-bold text-emerald-500 uppercase tracking-wider">Melhoria no Período</h3>
             </div>
             {comparisonLabel && (
                 <span className="text-[10px] text-slate-500 pl-6">{comparisonLabel}</span>
             )}
          </div>
          <div className="flex-1 overflow-y-auto custom-scrollbar">
            {improved.length === 0 ? <div className="text-center py-4 text-slate-600 text-xs">Sem registros.</div> : improved.map((item, idx) => renderCard(item, idx + 1, 'better'))}
          </div>
       </div>
    </div>
  );
};

