// --- Comparison Chart (Pareto vs Composition) ---
export const ComparisonChart: React.FC<ChartProps> = ({ data, isDarkMode, isExpanded }) => {
  const [viewMode, setViewMode] = useState<'composition' | 'ranking'>('composition');

  // Defensive check
  if (!data) return null;

  const aggregated = data.reduce((acc, curr) => {
    const found = acc.find(item => item.ug === curr.ug);
    if (found) {
      found.siafi += curr.siafiValue || 0;
      found.siloms += curr.silomsValue || 0;
      found.diff += curr.difference || 0;
      found.netDiff += (curr.silomsValue - curr.siafiValue); 
    } else {
      acc.push({ 
        ug: curr.ug, 
        siafi: curr.siafiValue || 0, 
        siloms: curr.silomsValue || 0, 
        diff: curr.difference || 0,
        netDiff: (curr.silomsValue - curr.siafiValue) || 0
      });
    }
    return acc;
  }, [] as { ug: string, siafi: number, siloms: number, diff: number, netDiff: number, accumulatedPct?: number }[]);

  // Sort by Magnitude (Difference) for Pareto
  aggregated.sort((a, b) => b.diff - a.diff);

  // Calculate Pareto Cumulative Percentage
  const totalAbsDiff = aggregated.reduce((sum, item) => sum + item.diff, 0);
  let accumulated = 0;
  const paretoData = aggregated.map(item => {
    accumulated += item.diff;
    return {
      ...item,
      accumulatedPct: totalAbsDiff > 0 ? (accumulated / totalAbsDiff) * 100 : 0
    };
  });

  const totalNetDivergence = aggregated.reduce((sum, item) => sum + item.netDiff, 0);

  // Decide how many items to show based on expansion
  const displayData = isExpanded ? paretoData : paretoData.slice(0, 15);

  if (displayData.length === 0) {
     return <div className="flex items-center justify-center h-full text-slate-500">Sem dados para exibir.</div>;
  }

  // Styles for scrolling logic
  const isHorizontalScroll = viewMode === 'composition' && isExpanded; // Composition expands horizontally
  const isVerticalScroll = false; // We fit to container usually unless huge

  const containerStyle = isExpanded && viewMode === 'composition'
      ? { width: `${Math.max(100, displayData.length * 70)}px`, height: '100%' }
      : { width: '100%', height: '100%' };

  // For Pareto in Expanded, we might want horizontal scroll if bars are thin, but typically Pareto is viewed as a whole or scrolled horizontally if huge. 
  // Let's allow horizontal scroll for Pareto as well if expanded to ensure labels are readable
  if (isExpanded && viewMode === 'ranking') {
     containerStyle.width = `${Math.max(100, displayData.length * 60)}px`;
  }

  const overflowClass = isExpanded 
    ? 'overflow-x-auto custom-scrollbar pb-2' 
    : '';

  return (
    <div className="flex flex-col h-full w-full relative">

      {/* View Toggle */}
      <div className="absolute top-0 right-10 sm:right-0 z-10 flex bg-slate-100 dark:bg-slate-700 rounded-lg p-0.5 border border-slate-200 dark:border-slate-600 shadow-sm">
        <button
          onClick={() => setViewMode('composition')}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-md transition-all
            ${viewMode === 'composition' 
              ? 'bg-white dark:bg-slate-600 text-slate-800 dark:text-white shadow-sm' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
            }`}
        >
          <BarChart3 className="w-3 h-3" />
          Composição
        </button>
        <button
          onClick={() => setViewMode('ranking')}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-md transition-all
            ${viewMode === 'ranking' 
              ? 'bg-white dark:bg-slate-600 text-slate-800 dark:text-white shadow-sm' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
            }`}
        >
          <LayoutList className="w-3 h-3" />
          Pareto
        </button>
      </div>

      {/* Expanded Only Metric */}
      {isExpanded && viewMode === 'composition' && (
        <div className={`mb-2 mr-36 px-3 py-2 rounded-lg border flex items-center justify-between max-w-md
           ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
           <span className="text-xs font-bold uppercase text-slate-400">
             Divergência Líquida
           </span>
           <span className={`text-sm font-mono font-bold
             ${totalNetDivergence > 0 ? 'text-emerald-500' : totalNetDivergence < 0 ? 'text-red-500' : 'text-slate-500'}
           `}>
             {totalNetDivergence > 0 ? '+' : ''}{formatCurrency(totalNetDivergence)}
           </span>
        </div>
      )}

      <div className={`flex-1 w-full min-h-0 mt-8 ${overflowClass}`}>
        <div style={containerStyle}>
          <ResponsiveContainer width="100%" height="100%">
            {viewMode === 'composition' ? (
              // COMPOSITION VIEW (Vertical Bars, Side-by-Side)
