                {/* Absolute Impact Bars (Purple) */}
                <Bar 
                  yAxisId="left"
                  dataKey="diff" 
                  name="Impacto Absoluto" 
                  fill="#6366f1" 
                  radius={[4, 4, 0, 0]} 
                  barSize={isExpanded ? undefined : 20}
                />

                {/* Accumulated Line (Orange) */}
                <Line 
                  yAxisId="right"
                  type="monotone" 
                  dataKey="accumulatedPct" 
                  name="Acumulado %" 
                  stroke="#f59e0b" 
                  strokeWidth={2}
                  dot={{ r: 3, fill: '#f59e0b', strokeWidth: 0 }}
                  activeDot={{ r: 5 }}
                />
              </ComposedChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

// --- Evolution Area Chart (Improved) ---

export const EvolutionChart: React.FC<ChartProps> = ({ data, isDarkMode }) => {
  if (!data) return null;

  const timeSeries = data.reduce((acc, curr) => {
    const found = acc.find(item => item.date === curr.date);
    if (found) {
      found.totalDiff += curr.difference;
    } else {
      acc.push({ 
        date: curr.date, 
        totalDiff: curr.difference, 
        timestamp: (curr.year * 100) + curr.monthIndex 
      });
    }
    return acc;
  }, [] as { date: string, totalDiff: number, timestamp: number }[]);

  timeSeries.sort((a, b) => a.timestamp - b.timestamp);

  if (timeSeries.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  return (
    <div className="w-full h-full min-h-[250px]">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={timeSeries} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          <defs>
            <linearGradient id="colorDiff" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#6366f1" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
          <XAxis 
            dataKey="date" 
            tickFormatter={(val) => val.split('/')[0].substring(0,3)}
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false} 
          />
          <YAxis 
            tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false}
          />
          <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} />
          <Area 
            type="monotone" 
            dataKey="totalDiff" 
            name="Diferença Total" 
            stroke="#6366f1" 
            fillOpacity={1} 
            fill="url(#colorDiff)" 
            strokeWidth={3}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { MessageSquareText, ArrowUpDown } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';
import { parseDateString } from '../services/dataProcessor';

interface TemporalHeatmapProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  availableMonths: string[];
  onSendMessage: (record: FinancialRecord) => void;
}

export const TemporalHeatmap: React.FC<TemporalHeatmapProps> = ({ 
  data, 
  isDarkMode, 
  availableMonths, 
  onSendMessage
}) => {
  const [internalGroupFilter, setInternalGroupFilter] = useState<string>('ALL');

  // Filter Data
  const filteredData = useMemo(() => data.filter(item => 
    internalGroupFilter === 'ALL' || item.group === internalGroupFilter
  ), [data, internalGroupFilter]);

  // --- DYNAMIC COLOR LOGIC (10 LEVELS - LOCAL SCALING) ---
  // Now accepts localMax to scale colors relative to the specific UG's history
  const getCellColor = (value: number, localMax: number) => {
    if (value === 0) return 'bg-slate-800/40 text-slate-600 font-normal border border-slate-800/50';

    // Prevent division by zero
    const ratio = localMax > 0 ? value / localMax : 0;

    // Level 1: Lowest (0-10%) - Deepest Green
    if (ratio <= 0.10) return 'bg-emerald-950/80 text-emerald-400 font-normal border border-emerald-900/30';

    // Level 2: Very Low (10-20%) - Deep Green
    if (ratio <= 0.20) return 'bg-emerald-900/80 text-emerald-300 font-normal border border-emerald-800/30';

    // Level 3: Low (20-30%) - Medium Green
    if (ratio <= 0.30) return 'bg-emerald-800 text-emerald-100 font-medium border border-emerald-700/30';

    // Level 4: Low-Mid (30-40%) - Standard Green
    if (ratio <= 0.40) return 'bg-emerald-600 text-white font-medium border border-emerald-500/30';

    // Level 5: Mid (40-50%) - Lime Transition
    if (ratio <= 0.50) return 'bg-lime-600 text-white font-medium border border-lime-500/30';

    // Level 6: Mid-High (50-60%) - Yellow/Dark Yellow
    if (ratio <= 0.60) return 'bg-yellow-600 text-white font-bold border border-yellow-500/30 shadow-sm';

    // Level 7: High (60-70%) - Amber
    if (ratio <= 0.70) return 'bg-amber-500 text-white font-bold border border-amber-400/30 shadow-sm';

    // Level 8: Very High (70-80%) - Orange
    if (ratio <= 0.80) return 'bg-orange-500 text-white font-bold border border-orange-400/30 shadow-sm';

    // Level 9: Severe (80-90%) - Red
    if (ratio <= 0.90) return 'bg-red-500 text-white font-bold border border-red-400/30 shadow-md';

    // Level 10: Critical (90-100%) - Deep Red
    return 'bg-[#450a0a] text-red-100 font-black border border-red-500 shadow-[inset_0_0_8px_rgba(0,0,0,0.6)]'; 
  };

  // Compact Number Formatter (399.3M, 931k)
  const formatCompact = (val: number) => {
    if (val === 0) return '-';
    if (val >= 1000000) return `${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `${(val / 1000).toFixed(0)}k`;
    return val.toFixed(0);
  };

  // Group Badge Color Helper - MONOCHROME/NEUTRAL
  const getGroupBadgeClass = (group: string) => {
    // All groups use neutral colors now
    return 'bg-slate-700 text-slate-300';
  };

  // Sort logic: Total Difference across all visible months
  const sortedUGs = useMemo(() => {
    const ugs = Array.from(new Set(filteredData.map(d => d.ug))) as string[];
    return ugs.sort((a, b) => {
      const sumA = filteredData.filter(r => r.ug === a).reduce((acc, r) => acc + r.difference, 0);
      const sumB = filteredData.filter(r => r.ug === b).reduce((acc, r) => acc + r.difference, 0);
      return sumB - sumA;
    });
  }, [filteredData]);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden text-xs bg-[#0b1120] rounded-lg border border-slate-700">

      {/* Header Controls */}
      <div className="flex items-center justify-between gap-2 p-2 border-b border-slate-700 bg-slate-800">
        <div className="flex items-center gap-2 overflow-x-auto">
           {[
               { id: 'ALL', label: 'TODOS', activeClass: 'text-slate-100 bg-slate-700' },
               { id: AccountGroup.BMP, label: 'BMP', activeClass: 'text-red-500 border border-red-500' },
               { id: AccountGroup.CONSUMO, label: 'CONSUMO', activeClass: 'text-blue-500 border border-blue-500' },
               { id: AccountGroup.INTANGIVEL, label: 'INTANGIVEL', activeClass: 'text-emerald-500 border border-emerald-500' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setInternalGroupFilter(tab.id)}
                className={`px-3 py-1 rounded text-[10px] font-bold uppercase transition-all whitespace-nowrap border border-transparent
                  ${internalGroupFilter === tab.id 
                    ? tab.activeClass 
                    : 'bg-slate-900 text-slate-400 hover:bg-slate-700 border-slate-600'
                  }
                `}
              >
                {tab.label}
              </button>
            ))}
        </div>

        <div className="hidden sm:flex items-center gap-1 px-2 py-1 rounded bg-slate-900 border border-slate-700 text-slate-400 text-[10px] font-bold uppercase">
           <ArrowUpDown className="w-3 h-3" />
           Maior Valor
        </div>
      </div>

      {sortedUGs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-2">
            <span className="text-lg">Sem dados para exibir</span>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#0b1120] relative">
          <div className="w-full min-w-[700px] p-2">

            {/* 
               GRID LAYOUT DEFINITION 
               Col 1: 180px fixed (Name)
               Col 2: Auto-fit (Months) - minmax(0, 1fr) ensures equal distribution without overflow
               Col 3: 40px fixed (Action)
            */}
            <div 
              className="grid gap-1 mb-2 sticky top-0 z-10 bg-[#0b1120] pb-2 border-b border-slate-800 items-end"
              style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(0, 1fr)) 40px` }}
            >
                <div className="text-slate-500 font-bold uppercase tracking-wider pl-2 text-[10px]">UG / GRUPO</div>

                {availableMonths.map(month => (
                    <div key={month} className="text-center text-slate-500 font-bold uppercase text-[10px] truncate px-1">
                        {month.split('/')[0].substring(0, 3)}/{month.split('/')[1]?.substring(2,4)}
                    </div>
                ))}

                <div className="text-center text-slate-500 font-bold text-[10px]">MSG</div>
            </div>

            {/* Rows */}
            <div className="space-y-1">
              {sortedUGs.map(ug => {
                const ugRecords = filteredData.filter(d => d.ug === ug);
                const uniqueGroups = (Array.from(new Set(ugRecords.map(r => r.group))) as AccountGroup[]).sort();

                return uniqueGroups.map(group => {
                   // Calculate Local Max for this specific UG/Group combination across all loaded dates
                   const groupRecords = ugRecords.filter(r => r.group === group);
                   const localMax = groupRecords.length > 0 
                     ? Math.max(...groupRecords.map(r => r.difference)) 
                     : 1;

                   // Styles now depend on just being neutral
                   const groupClass = 'bg-slate-700 text-slate-300';
                   return (
                    <div 
                        key={`${ug}-${group}`} 
                        className="grid gap-1 items-center hover:bg-slate-800/30 rounded transition-colors"
                        style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(0, 1fr)) 40px` }}
                    >

                        {/* Name Column */}
                        <div className="flex items-center h-8 overflow-hidden rounded bg-slate-800/80 border border-slate-700/50">
                            <div className={`w-8 h-full flex items-center justify-center text-[8px] font-black uppercase ${groupClass}`}>
                                {group === AccountGroup.BMP ? 'BMP' : group === AccountGroup.CONSUMO ? 'CN' : 'INT'}
                            </div>
                            <div className="flex-1 px-2 text-slate-300 font-semibold truncate text-[10px]">
                                {ug}
                            </div>
                        </div>

                        {/* Months Data Cells */}
                        {availableMonths.map(month => {
                            const record = ugRecords.find(r => r.date === month && r.group === group);
                            const diff = record ? record.difference : 0;

                            return (
                                <div 
                                    key={month}
                                    className={`h-8 rounded flex items-center justify-center text-[10px] transition-all cursor-help border-transparent border
                                        ${getCellColor(diff, localMax)}
                                    `}
                                    title={record ? `${month}: R$ ${diff.toLocaleString('pt-BR')}` : 'Sem dados'}
                                >
                                    {formatCompact(diff)}
                                </div>
                            );
                        })}

                        {/* Action Column */}
                        <div className="flex justify-center h-8">
                             <button 
                                onClick={() => {
                                    const latest = ugRecords.filter(r => r.group === group).sort((a, b) => parseDateString(b.date).timestamp - parseDateString(a.date).timestamp)[0];
                                    if(latest) onSendMessage(latest);
                                }}
                                className="w-8 h-8 flex items-center justify-center rounded bg-slate-800 text-slate-500 hover:text-white hover:bg-blue-600 transition-colors border border-slate-700"
                             >
                                 <MessageSquareText className="w-3.5 h-3.5" />
                             </button>
                        </div>
                    </div>
                   );
                });
              })}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
  LineChart, Line, TooltipProps, ComposedChart, AreaChart, Area
} from 'recharts';
import { FinancialRecord } from '../types';
import { formatCurrency } from '../services/dataProcessor';
import { LayoutList, BarChart3 } from 'lucide-react';

interface ChartProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  isExpanded?: boolean;
}

// --- Custom Tooltip (Neon Style) ---
const CustomDetailedTooltip = ({ active, payload, label, isDarkMode }: any) => {
  if (active && payload && payload.length) {
    const data = payload[0].payload;
    // Values might come from different properties depending on the chart type
    // We prioritize the ones passed in payload or fallback to data attributes
    const diff = data.diff !== undefined ? data.diff : data.totalDiff;
    const siafi = data.siafi !== undefined ? data.siafi : data.totalSiafi;
    const siloms = data.siloms !== undefined ? data.siloms : data.totalSiloms;
    const pct = data.accumulatedPct; // For Pareto

    return (
      <div className={`min-w-[220px] p-4 rounded-xl border shadow-2xl backdrop-blur-md z-50 
        ${isDarkMode ? 'bg-[#0f172a]/95 border-slate-700' : 'bg-white/95 border-slate-200'}
      `}>
        <h4 className={`text-base font-black mb-3 pb-2 border-b uppercase tracking-wider
          ${isDarkMode ? 'text-white border-slate-700' : 'text-slate-900 border-slate-200'}
        `}>
          {label || data.ug}
        </h4>

        <div className="space-y-3">
           {/* Acumulado (Only for Pareto) */}
           {pct !== undefined && (
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <div className="w-2 h-2 rounded-full bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.6)]"></div>
                   <span className={`text-xs font-bold ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>Acumulado:</span>
                </div>
                <span className="text-sm font-bold font-mono text-amber-500">{pct.toFixed(1)}%</span>
             </div>
           )}

           {/* Difference */}
           <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                 <div className="w-2 h-2 rounded-full bg-[#6366f1] shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
                 <span className={`text-xs font-bold ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>Diferença:</span>
              </div>
              <span className={`text-sm font-bold font-mono ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>
                {formatCurrency(diff)}
              </span>
           </div>

           {/* SIAFI */}
           {siafi !== undefined && (
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <div className="w-2 h-2 rounded-full bg-[#3b82f6] shadow-[0_0_8px_rgba(59,130,246,0.6)]"></div>
                   <span className={`text-xs font-bold ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>SIAFI:</span>
                </div>
                <span className="text-sm font-bold font-mono text-blue-400">{formatCurrency(siafi)}</span>
             </div>
           )}

           {/* SILOMS */}
           {siloms !== undefined && (
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                   <div className="w-2 h-2 rounded-full bg-[#10b981] shadow-[0_0_8px_rgba(16,185,129,0.6)]"></div>
                   <span className={`text-xs font-bold ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>SILOMS:</span>
                </div>
                <span className="text-sm font-bold font-mono text-emerald-400">{formatCurrency(siloms)}</span>
             </div>
           )}
        </div>
      </div>
    );
  }
  return null;
};

// --- Comparison Chart (Pareto vs Composition) ---
export const ComparisonChart: React.FC<ChartProps> = ({ data, isDarkMode, isExpanded }) => {
  const [viewMode, setViewMode] = useState<'composition' | 'ranking'>('composition');

  // Defensive check
  if (!data) return null;

  const aggregated = data.reduce((acc, curr) => {
    const found = acc.find(item => item.ug === curr.ug);
    if (found) {
      found.siafi += curr.siafiValue || 0;
      found.siloms += curr.silomsValue || 0;
      found.diff += curr.difference || 0;
      found.netDiff += (curr.silomsValue - curr.siafiValue); 
    } else {
      acc.push({ 
        ug: curr.ug, 
        siafi: curr.siafiValue || 0, 
        siloms: curr.silomsValue || 0, 
        diff: curr.difference || 0,
        netDiff: (curr.silomsValue - curr.siafiValue) || 0
      });
    }
    return acc;
  }, [] as { ug: string, siafi: number, siloms: number, diff: number, netDiff: number, accumulatedPct?: number }[]);

  // Sort by Magnitude (Difference) for Pareto
  aggregated.sort((a, b) => b.diff - a.diff);

  // Calculate Pareto Cumulative Percentage
  const totalAbsDiff = aggregated.reduce((sum, item) => sum + item.diff, 0);
  let accumulated = 0;
  const paretoData = aggregated.map(item => {
    accumulated += item.diff;
    return {
      ...item,
      accumulatedPct: totalAbsDiff > 0 ? (accumulated / totalAbsDiff) * 100 : 0
    };
  });

  const totalNetDivergence = aggregated.reduce((sum, item) => sum + item.netDiff, 0);

  // Decide how many items to show based on expansion
  const displayData = isExpanded ? paretoData : paretoData.slice(0, 15);

  if (displayData.length === 0) {
     return <div className="flex items-center justify-center h-full text-slate-500">Sem dados para exibir.</div>;
  }

  // Styles for scrolling logic
  const containerStyle = isExpanded && viewMode === 'composition'
      ? { width: `${Math.max(100, displayData.length * 70)}px`, height: '100%' }
      : { width: '100%', height: '100%' };

  if (isExpanded && viewMode === 'ranking') {
     containerStyle.width = `${Math.max(100, displayData.length * 60)}px`;
  }

  const overflowClass = isExpanded 
    ? 'overflow-x-auto custom-scrollbar pb-2' 
    : '';

  return (
    <div className="flex flex-col h-full w-full relative">

      {/* View Toggle */}
      <div className="absolute top-0 right-10 sm:right-0 z-10 flex bg-slate-100 dark:bg-slate-700 rounded-lg p-0.5 border border-slate-200 dark:border-slate-600 shadow-sm">
        <button
          onClick={() => setViewMode('composition')}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-md transition-all
            ${viewMode === 'composition' 
              ? 'bg-white dark:bg-slate-600 text-slate-800 dark:text-white shadow-sm' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
            }`}
        >
          <BarChart3 className="w-3 h-3" />
          Composição
        </button>
        <button
          onClick={() => setViewMode('ranking')}
          className={`flex items-center gap-2 px-3 py-1.5 text-xs font-bold rounded-md transition-all
            ${viewMode === 'ranking' 
              ? 'bg-white dark:bg-slate-600 text-slate-800 dark:text-white shadow-sm' 
              : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
            }`}
        >
          <LayoutList className="w-3 h-3" />
          Pareto
        </button>
      </div>

      {/* Expanded Only Metric */}
      {isExpanded && viewMode === 'composition' && (
        <div className={`mb-2 mr-36 px-3 py-2 rounded-lg border flex items-center justify-between max-w-md
           ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
           <span className="text-xs font-bold uppercase text-slate-400">
             Divergência Líquida
           </span>
           <span className={`text-sm font-mono font-bold
             ${totalNetDivergence > 0 ? 'text-emerald-500' : totalNetDivergence < 0 ? 'text-red-500' : 'text-slate-500'}
           `}>
             {totalNetDivergence > 0 ? '+' : ''}{formatCurrency(totalNetDivergence)}
           </span>
        </div>
      )}

      <div className={`flex-1 w-full min-h-0 mt-8 ${overflowClass}`}>
        <div style={containerStyle}>
          <ResponsiveContainer width="100%" height="100%">
            {viewMode === 'composition' ? (
              // COMPOSITION VIEW (Vertical Bars, Side-by-Side)
              <BarChart data={displayData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                <XAxis 
                  dataKey="ug" 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 11}} 
                  interval={0}
                  angle={isExpanded ? -45 : 0}
                  textAnchor={isExpanded ? 'end' : 'middle'}
                  height={isExpanded ? 60 : 30}
                  axisLine={false} 
                  tickLine={false} 
                />
                <YAxis 
                  tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
                  axisLine={false} 
                  tickLine={false}
                />
                <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} cursor={{fill: isDarkMode ? '#1e293b' : '#f1f5f9'}} />
                <Legend wrapperStyle={{ paddingTop: '10px' }} />
                <Bar dataKey="siafi" name="SIAFI" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                <Bar dataKey="siloms" name="SILOMS" fill="#10b981" radius={[4, 4, 0, 0]} />
              </BarChart>
            ) : (
              // PARETO VIEW (Composed Chart: Bar + Line)
              <ComposedChart data={displayData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
                <XAxis 
                  dataKey="ug" 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b', fontSize: 11}} 
                  interval={0}
                  angle={isExpanded ? -45 : 0}
                  textAnchor={isExpanded ? 'end' : 'middle'}
                  height={isExpanded ? 60 : 30}
                  axisLine={false} 
                  tickLine={false} 
                />
                {/* Left Axis: Values */}
                <YAxis 
                  yAxisId="left"
                  tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
                  tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
                  axisLine={false} 
                  tickLine={false}
                />
                {/* Right Axis: Percentage */}
                <YAxis 
                  yAxisId="right"
                  orientation="right"
                  tickFormatter={(value) => `${value}%`} 
                  tick={{fill: isDarkMode ? '#fbbf24' : '#d97706'}} 
                  axisLine={false} 
                  tickLine={false}
                  domain={[0, 100]}
                />
                <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} />
                <Legend wrapperStyle={{ paddingTop: '10px' }} />

                {/* Absolute Impact Bars (Purple) */}
                <Bar 
                  yAxisId="left"
                  dataKey="diff" 
                  name="Impacto Absoluto" 
                  fill="#6366f1" 
                  radius={[4, 4, 0, 0]} 
                  barSize={isExpanded ? undefined : 20}
                />

                {/* Accumulated Line (Orange) */}
                <Line 
                  yAxisId="right"
                  type="monotone" 
                  dataKey="accumulatedPct" 
                  name="Acumulado %" 
                  stroke="#f59e0b" 
                  strokeWidth={2}
                  dot={{ r: 3, fill: '#f59e0b', strokeWidth: 0 }}
                  activeDot={{ r: 5 }}
                />
              </ComposedChart>
            )}
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

// --- Evolution Area Chart (Improved with Extra Data for Tooltip) ---

export const EvolutionChart: React.FC<ChartProps> = ({ data, isDarkMode }) => {
  if (!data) return null;

  const timeSeries = data.reduce((acc, curr) => {
    const found = acc.find(item => item.date === curr.date);
    if (found) {
      found.totalDiff += curr.difference;
      found.totalSiafi += curr.siafiValue; // Accumulate for tooltip
      found.totalSiloms += curr.silomsValue; // Accumulate for tooltip
    } else {
      acc.push({ 
        date: curr.date, 
        totalDiff: curr.difference, 
        totalSiafi: curr.siafiValue,
        totalSiloms: curr.silomsValue,
        timestamp: (curr.year * 100) + curr.monthIndex 
      });
    }
    return acc;
  }, [] as { date: string, totalDiff: number, totalSiafi: number, totalSiloms: number, timestamp: number }[]);

  timeSeries.sort((a, b) => a.timestamp - b.timestamp);

  if (timeSeries.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  return (
    <div className="w-full h-full min-h-[250px]">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={timeSeries} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          <defs>
            <linearGradient id="colorDiff" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#6366f1" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
          <XAxis 
            dataKey="date" 
            tickFormatter={(val) => val.split('/')[0].substring(0,3)}
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false} 
          />
          <YAxis 
            tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false}
          />
          {/* We pass all data to tooltip via the payload of the area */}
          <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} />
          <Area 
            type="monotone" 
            dataKey="totalDiff" 
            name="Diferença Total" 
            stroke="#6366f1" 
            fillOpacity={1} 
            fill="url(#colorDiff)" 
            strokeWidth={3}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

