import React, { useState, useMemo } from 'react';
import { MessageSquareText, ArrowUpDown } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';
import { parseDateString } from '../services/dataProcessor';

interface TemporalHeatmapProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  availableMonths: string[];
  onSendMessage: (record: FinancialRecord) => void;
}

export const TemporalHeatmap: React.FC<TemporalHeatmapProps> = ({ 
  data, 
  isDarkMode, 
  availableMonths, 
  onSendMessage
}) => {
  const [internalGroupFilter, setInternalGroupFilter] = useState<string>('ALL');

  // Filter Data
  const filteredData = useMemo(() => data.filter(item => 
    internalGroupFilter === 'ALL' || item.group === internalGroupFilter
  ), [data, internalGroupFilter]);

  // --- DYNAMIC NEON COLOR LOGIC (10 LEVELS) ---
  const getCellColor = (value: number, localMax: number) => {
    if (value === 0) return 'bg-slate-800/40 text-slate-600 font-normal border border-slate-800/50';

    // Prevent division by zero
    const ratio = localMax > 0 ? value / localMax : 0;

    // VIBRANT NEON PALETTE
    // 0-10%: Dark but Green
    if (ratio <= 0.10) return 'bg-[#064e3b] text-emerald-400 font-normal border border-emerald-900/30';

    // 10-20%: Emerald Green
    if (ratio <= 0.20) return 'bg-[#10b981] text-black font-bold shadow-[0_0_5px_rgba(16,185,129,0.3)]';

    // 20-30%: Bright Lime Green
    if (ratio <= 0.30) return 'bg-[#84cc16] text-black font-bold shadow-[0_0_5px_rgba(132,204,22,0.4)]';

    // 30-40%: Yellow Green
    if (ratio <= 0.40) return 'bg-[#a3e635] text-black font-bold shadow-[0_0_5px_rgba(163,230,53,0.4)]';

    // 40-50%: Yellow
    if (ratio <= 0.50) return 'bg-[#facc15] text-black font-bold shadow-[0_0_5px_rgba(250,204,21,0.5)]';

    // 50-60%: Amber/Gold
    if (ratio <= 0.60) return 'bg-[#fbbf24] text-black font-bold shadow-[0_0_5px_rgba(251,191,36,0.5)]';

    // 60-70%: Orange
    if (ratio <= 0.70) return 'bg-[#f97316] text-white font-bold shadow-[0_0_5px_rgba(249,115,22,0.5)]';

    // 70-80%: Bright Orange/Red
    if (ratio <= 0.80) return 'bg-[#ea580c] text-white font-bold shadow-[0_0_5px_rgba(234,88,12,0.5)]';

    // 80-90%: Red
    if (ratio <= 0.90) return 'bg-[#dc2626] text-white font-bold shadow-[0_0_8px_rgba(220,38,38,0.6)]';

    // 90-100%: Deep Neon Red
    return 'bg-[#991b1b] text-red-100 font-black border border-red-500 shadow-[0_0_10px_rgba(153,27,27,0.8)]'; 
  };

  // Compact Number Formatter (399.3M, 931k)
  const formatCompact = (val: number) => {
    if (val === 0) return '-';
    if (val >= 1000000) return `${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `${(val / 1000).toFixed(0)}k`;
    return val.toFixed(0);
  };

  // Group Badge Color Helper - NEON COLORS
  const getGroupBadgeClass = (group: string) => {
    if (group === AccountGroup.BMP) 
      return 'bg-red-500/20 text-red-400 border border-red-500/30';
    if (group === AccountGroup.CONSUMO) 
      return 'bg-blue-500/20 text-blue-400 border border-blue-500/30';
    if (group === AccountGroup.INTANGIVEL) 
      return 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30';
    return 'bg-slate-700 text-slate-300';
  };

  // Sort logic: Total Difference across all visible months
  const sortedUGs = useMemo(() => {
    const ugs = Array.from(new Set(filteredData.map(d => d.ug))) as string[];
    return ugs.sort((a, b) => {
      const sumA = filteredData.filter(r => r.ug === a).reduce((acc, r) => acc + r.difference, 0);
      const sumB = filteredData.filter(r => r.ug === b).reduce((acc, r) => acc + r.difference, 0);
      return sumB - sumA;
    });
  }, [filteredData]);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden text-xs bg-[#0b1120] rounded-lg border border-slate-700">

      {/* Header Controls */}
      <div className="flex items-center justify-between gap-2 p-2 border-b border-slate-700 bg-slate-800">
        <div className="flex items-center gap-2 overflow-x-auto">
           {[
               { id: 'ALL', label: 'TODOS', activeClass: 'text-slate-100 bg-slate-700' },
               { id: AccountGroup.BMP, label: 'BMP', activeClass: 'text-red-500 border border-red-500' },
               { id: AccountGroup.CONSUMO, label: 'CONSUMO', activeClass: 'text-blue-500 border border-blue-500' },
               { id: AccountGroup.INTANGIVEL, label: 'INTANGIVEL', activeClass: 'text-emerald-500 border border-emerald-500' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setInternalGroupFilter(tab.id)}
                className={`px-3 py-1 rounded text-[10px] font-bold uppercase transition-all whitespace-nowrap border border-transparent
                  ${internalGroupFilter === tab.id 
                    ? tab.activeClass 
                    : 'bg-slate-900 text-slate-400 hover:bg-slate-700 border-slate-600'
                  }
                `}
              >
                {tab.label}
              </button>
            ))}
        </div>

        <div className="hidden sm:flex items-center gap-1 px-2 py-1 rounded bg-slate-900 border border-slate-700 text-slate-400 text-[10px] font-bold uppercase">
           <ArrowUpDown className="w-3 h-3" />
           Maior Valor
        </div>
      </div>

      {sortedUGs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-2">
            <span className="text-lg">Sem dados para exibir</span>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#0b1120] relative">
          <div className="w-full min-w-[700px] p-2">

            {/* 
               GRID LAYOUT DEFINITION 
               Col 1: 180px fixed (Name)
               Col 2: Auto-fit (Months) - minmax(0, 1fr) ensures equal distribution without overflow
               Col 3: 40px fixed (Action)
            */}
            <div 
              className="grid gap-1 mb-2 sticky top-0 z-10 bg-[#0b1120] pb-2 border-b border-slate-800 items-end"
              style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(0, 1fr)) 40px` }}
            >
                <div className="text-slate-500 font-bold uppercase tracking-wider pl-2 text-[10px]">UG / GRUPO</div>

                {availableMonths.map(month => (
                    <div key={month} className="text-center text-slate-500 font-bold uppercase text-[10px] truncate px-1">
                        {month.split('/')[0].substring(0, 3)}/{month.split('/')[1]?.substring(2,4)}
                    </div>
                ))}

                <div className="text-center text-slate-500 font-bold text-[10px]">MSG</div>
            </div>

            {/* Rows */}
            <div className="space-y-1">
              {sortedUGs.map(ug => {
                const ugRecords = filteredData.filter(d => d.ug === ug);
                const uniqueGroups = (Array.from(new Set(ugRecords.map(r => r.group))) as AccountGroup[]).sort();

                return uniqueGroups.map(group => {
                   // Calculate Local Max for this specific UG/Group combination across all loaded dates
                   const groupRecords = ugRecords.filter(r => r.group === group);
                   const localMax = groupRecords.length > 0 
                     ? Math.max(...groupRecords.map(r => r.difference)) 
                     : 1;

                   return (
                    <div 
                        key={`${ug}-${group}`} 
                        className="grid gap-1 items-center hover:bg-slate-800/30 rounded transition-colors"
                        style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(0, 1fr)) 40px` }}
                    >

                        {/* Name Column */}
                        <div className="flex items-center h-8 overflow-hidden rounded bg-slate-800/80 border border-slate-700/50">
                            <div className={`w-8 h-full flex items-center justify-center text-[8px] font-black uppercase ${getGroupBadgeClass(group)}`}>
                                {group === AccountGroup.BMP ? 'BMP' : group === AccountGroup.CONSUMO ? 'CN' : 'INT'}
                            </div>
                            <div className="flex-1 px-2 text-slate-300 font-semibold truncate text-[10px]">
                                {ug}
                            </div>
                        </div>

                        {/* Months Data Cells */}
                        {availableMonths.map(month => {
                            const record = ugRecords.find(r => r.date === month && r.group === group);
                            const diff = record ? record.difference : 0;

                            return (
                                <div 
                                    key={month}
                                    className={`h-8 rounded flex items-center justify-center text-[10px] transition-all cursor-help border-transparent border
                                        ${getCellColor(diff, localMax)}
                                    `}
                                    title={record ? `${month}: R$ ${diff.toLocaleString('pt-BR')}` : 'Sem dados'}
                                >
                                    {formatCompact(diff)}
                                </div>
                            );
                        })}

                        {/* Action Column */}
                        <div className="flex justify-center h-8">
                             <button 
                                onClick={() => {
                                    const latest = ugRecords.filter(r => r.group === group).sort((a, b) => parseDateString(b.date).timestamp - parseDateString(a.date).timestamp)[0];
                                    if(latest) onSendMessage(latest);
                                }}
                                className="w-8 h-8 flex items-center justify-center rounded bg-slate-800 text-slate-500 hover:text-white hover:bg-blue-600 transition-colors border border-slate-700"
                             >
                                 <MessageSquareText className="w-3.5 h-3.5" />
                             </button>
                        </div>
                    </div>
                   );
                });
              })}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { normalizeData, formatCurrency, parseDateString, recalculateDeltas } from './services/dataProcessor';
import { parseExcelFile } from './services/excelParser';
import { AccountGroup, TimeFilter, FinancialRecord } from './types';
import { StatCard } from './components/StatCard';
import { ComparisonChart, EvolutionChart } from './components/Charts';
import { RankingList } from './components/RankingList';
import { TemporalHeatmap } from './components/TemporalHeatmap';
import { ChartWrapper } from './components/ChartWrapper';
import { FileUploadModal } from './components/FileUploadModal';
import { SiafiMessageModal } from './components/SiafiMessageModal';
import { CustomSelect } from './components/CustomSelect'; // Custom Component
import { 
  Activity, AlertTriangle, FileSpreadsheet, TrendingUp, Search, 
  LayoutDashboard, Layers, UploadCloud, Sun, Moon 
} from 'lucide-react';

function App() {
  // START EMPTY (No Mock Data)
  const [rawData, setRawData] = useState<any[]>([]);

  // UI State
  const [selectedGroup, setSelectedGroup] = useState<string>('ALL');
  const [timeFilter, setTimeFilter] = useState<TimeFilter>('MENSAL');
  const [selectedMonth, setSelectedMonth] = useState<string>('');
  const [selectedUG, setSelectedUG] = useState<string>('TODOS'); // New Global Filter
  const [searchTerm, setSearchTerm] = useState('');
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [hideZeros, setHideZeros] = useState(true);

  // Modals
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isMessageModalOpen, setIsMessageModalOpen] = useState(false);
  const [selectedRecordForMessage, setSelectedRecordForMessage] = useState<FinancialRecord | null>(null);

  // Effect: Enforce Dark Mode on Body
  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  // 1. PROCESS DATA: Normalize -> Recalculate Deltas
  const allData = useMemo(() => {
    const normalized = normalizeData(rawData);
    // Recalculate deltas based on whether we are looking Month-over-Month or Year-over-Year, etc.
    return recalculateDeltas(normalized, timeFilter);
  }, [rawData, timeFilter]);

  // 2. EXTRACT DROPDOWN LISTS
  const uniqueMonths = useMemo(() => {
    const dates = Array.from(new Set(allData.map(d => d.date))) as string[];
    return dates.sort((a, b) => parseDateString(a).timestamp - parseDateString(b).timestamp);
  }, [allData]);

  const uniqueUGs = useMemo(() => Array.from(new Set(allData.map(d => d.ug))).sort(), [allData]);

  // Auto-select latest month when data loads
  useEffect(() => {
    if (uniqueMonths.length > 0 && !selectedMonth) {
      setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    } else if (uniqueMonths.length > 0 && !uniqueMonths.includes(selectedMonth)) {
        // If current selection is invalid after new upload
        setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    }
  }, [uniqueMonths, selectedMonth]);

  // 3. FILTERING
  const filteredData = useMemo(() => {
    return allData.filter(item => {
      const matchSearch = item.ug.toLowerCase().includes(searchTerm.toLowerCase()) || item.cod.includes(searchTerm);
      const matchUG = selectedUG === 'TODOS' || item.ug === selectedUG;
      const matchZero = hideZeros ? item.difference !== 0 : true;
      // Note: Group filtering is handled at visual level for some components, or here for totals
      return matchSearch && matchZero && matchUG;
    });
  }, [allData, searchTerm, hideZeros, selectedUG]);

  // Subset: Current Month Only (For KPIs only)
  const currentMonthData = useMemo(() => {
    return filteredData.filter(item => 
        item.date === selectedMonth && 
        (selectedGroup === 'ALL' || item.group === selectedGroup)
    );
  }, [filteredData, selectedMonth, selectedGroup]);

  // Subset: Heatmap (Needs all months, ignores Global Group Filter for internal tabs)
  const heatmapData = useMemo(() => {
    return filteredData; // Contains all months, search applied, zeros hidden
  }, [filteredData]);

  // 4. KPI CALCULATIONS
  const stats = useMemo(() => {
    const totalDiff = currentMonthData.reduce((acc, curr) => acc + curr.difference, 0);
    const totalSiafi = currentMonthData.reduce((acc, curr) => acc + curr.siafiValue, 0);
    const totalSiloms = currentMonthData.reduce((acc, curr) => acc + curr.silomsValue, 0);
    const topOffender = currentMonthData.length > 0 
        ? currentMonthData.reduce((prev, current) => (prev.difference > current.difference) ? prev : current)
        : null;
    return { totalDiff, totalSiafi, totalSiloms, topOffender };
  }, [currentMonthData]);

  // Determine Comparison Label for Ranking
  const comparisonLabel = useMemo(() => {
     if (!selectedMonth || currentMonthData.length === 0) return `Comparando ${timeFilter}`;
     const sampleRecord = currentMonthData[0];
     const prevDate = sampleRecord.previousDate || 'N/A';
     // Extract short names e.g., JANEIRO/2025 -> JAN
     const currShort = selectedMonth.split('/')[0].substring(0,3);
     const prevShort = prevDate.includes('/') ? prevDate.split('/')[0].substring(0,3) : prevDate;

     return `Comparando ${currShort} contra ${prevShort}`;
  }, [currentMonthData, selectedMonth, timeFilter]);

  // Handlers
  const handleFileUpload = async (file: File) => {
    try {
      const parsed = await parseExcelFile(file);
      if (parsed.length > 0) {
        setRawData(parsed);
        alert(`Sucesso! ${parsed.length} linhas processadas.`);
      } else {
        alert("Arquivo vazio ou formato não reconhecido.");
      }
    } catch (e) {
      console.error(e);
      alert("Erro crítico ao processar arquivo. Verifique se é um Excel válido.");
    }
  };

  return (
    <div className={`min-h-screen pb-12 transition-colors duration-300 ${isDarkMode ? 'bg-[#020617] text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      <FileUploadModal 
        isOpen={isUploadModalOpen} 
