import React, { useState, useMemo } from 'react';
import { MessageSquareText, ArrowUpDown } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';
import { parseDateString } from '../services/dataProcessor';

interface TemporalHeatmapProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  availableMonths: string[];
  onSendMessage: (record: FinancialRecord) => void;
}

export const TemporalHeatmap: React.FC<TemporalHeatmapProps> = ({ 
  data, 
  isDarkMode, 
  availableMonths, 
  onSendMessage
}) => {
  const [internalGroupFilter, setInternalGroupFilter] = useState<string>('ALL');

  // Filter Data
  const filteredData = useMemo(() => data.filter(item => 
    internalGroupFilter === 'ALL' || item.group === internalGroupFilter
  ), [data, internalGroupFilter]);

  // --- GOLD & GREEN PALETTE (Matching Reference Image) ---
  const getCellColor = (value: number, localMax: number) => {
    if (value === 0) return 'bg-slate-800/40 text-slate-600 font-normal border border-slate-800/50';

    // Prevent division by zero
    const ratio = localMax > 0 ? value / localMax : 0;

    // Palette: Green (Low) -> Olive (Mid) -> Gold/Mustard (High)

    // Very Low (0-15%): Dark Forest Green
    if (ratio <= 0.15) return 'bg-[#14532d] text-emerald-100 font-medium border border-[#14532d]'; 

    // Low (15-30%): Green
    if (ratio <= 0.30) return 'bg-[#15803d] text-white font-bold border border-[#15803d]';

    // Mid (30-50%): Olive / Lime Dark
    if (ratio <= 0.50) return 'bg-[#4d7c0f] text-white font-bold border border-[#4d7c0f]';

    // High (50-75%): Mustard / Dark Yellow
    if (ratio <= 0.75) return 'bg-[#a16207] text-white font-black border border-[#a16207]';

    // Max (75-100%): Gold / Brownish
    return 'bg-[#854d0e] text-amber-50 font-black border border-[#854d0e] shadow-sm'; 
  };

  // Compact Number Formatter (399.3M, 931k)
  const formatCompact = (val: number) => {
    if (val === 0) return '-';
    if (val >= 1000000) return `${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `${(val / 1000).toFixed(0)}k`;
    return val.toFixed(0);
  };

  // Group Badge Color Helper
  const getGroupBadgeClass = (group: string) => {
    // Standard Neutral style as base, but clean
    return 'bg-slate-100 text-slate-800 border border-slate-300 font-bold';
  };

  // Sort logic: Total Difference across all visible months
  const sortedUGs = useMemo(() => {
    const ugs = Array.from(new Set(filteredData.map(d => d.ug))) as string[];
    return ugs.sort((a, b) => {
      const sumA = filteredData.filter(r => r.ug === a).reduce((acc, r) => acc + r.difference, 0);
      const sumB = filteredData.filter(r => r.ug === b).reduce((acc, r) => acc + r.difference, 0);
      return sumB - sumA;
    });
  }, [filteredData]);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden text-sm bg-[#0f172a] rounded-lg border border-slate-700">

      {/* Header Controls */}
      <div className="flex items-center justify-between gap-2 p-3 border-b border-slate-700 bg-slate-800">
        <div className="flex items-center gap-2 overflow-x-auto">
           {[
               { id: 'ALL', label: 'TODOS', activeClass: 'text-slate-100 bg-slate-700' },
               { id: AccountGroup.BMP, label: 'BMP', activeClass: 'text-white bg-slate-600 border-slate-500' },
               { id: AccountGroup.CONSUMO, label: 'CONSUMO', activeClass: 'text-white bg-slate-600 border-slate-500' },
               { id: AccountGroup.INTANGIVEL, label: 'INTANGIVEL', activeClass: 'text-white bg-slate-600 border-slate-500' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setInternalGroupFilter(tab.id)}
                className={`px-4 py-1.5 rounded text-xs font-bold uppercase transition-all whitespace-nowrap border border-transparent
                  ${internalGroupFilter === tab.id 
                    ? tab.activeClass 
                    : 'bg-slate-900 text-slate-400 hover:bg-slate-700 border-slate-600'
                  }
                `}
              >
                {tab.label}
              </button>
            ))}
        </div>

        <div className="hidden sm:flex items-center gap-1 px-3 py-1.5 rounded bg-slate-900 border border-slate-700 text-slate-400 text-xs font-bold uppercase">
           <ArrowUpDown className="w-3 h-3" />
           Maior Valor
        </div>
      </div>

      {sortedUGs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-2">
            <span className="text-lg">Sem dados para exibir</span>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-[#0f172a] relative">
          <div className="w-full min-w-[900px] p-3">

            {/* 
               GRID LAYOUT DEFINITION - EXPANDED
               Col 1: 180px fixed (Name)
               Col 2: Auto-fit (Months) - minmax(100px, 1fr) for wider columns
               Col 3: 50px fixed (Action)
            */}
            <div 
              className="grid gap-1 mb-2 sticky top-0 z-10 bg-[#0f172a] pb-2 border-b border-slate-800 items-end"
              style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(100px, 1fr)) 50px` }}
            >
                <div className="text-slate-400 font-bold uppercase tracking-wider pl-2 text-xs">UG / GRUPO</div>

                {availableMonths.map(month => (
                    <div key={month} className="text-center text-slate-400 font-bold uppercase text-xs truncate px-1">
                        {month.split('/')[0].substring(0, 3)}
                    </div>
                ))}

                <div className="text-center text-slate-400 font-bold text-xs">MSG</div>
            </div>

            {/* Rows - EXPANDED HEIGHT (h-12) */}
            <div className="space-y-1.5">
              {sortedUGs.map(ug => {
                const ugRecords = filteredData.filter(d => d.ug === ug);
                const uniqueGroups = (Array.from(new Set(ugRecords.map(r => r.group))) as AccountGroup[]).sort();

                return uniqueGroups.map(group => {
                   // Calculate Local Max for this specific UG/Group combination across all loaded dates
                   const groupRecords = ugRecords.filter(r => r.group === group);
                   const localMax = groupRecords.length > 0 
                     ? Math.max(...groupRecords.map(r => r.difference)) 
                     : 1;

                   return (
                    <div 
                        key={`${ug}-${group}`} 
                        className="grid gap-1 items-center hover:bg-slate-800/30 rounded transition-colors"
                        style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(100px, 1fr)) 50px` }}
                    >

                        {/* Name Column */}
                        <div className="flex items-center h-12 overflow-hidden rounded bg-slate-800/50 border border-slate-700/50">
                            <div className={`w-10 h-full flex items-center justify-center text-[9px] font-black uppercase ${getGroupBadgeClass(group)}`}>
                                {group === AccountGroup.BMP ? 'BMP' : group === AccountGroup.CONSUMO ? 'CN' : 'INT'}
                            </div>
                            <div className="flex-1 px-3 text-slate-200 font-bold truncate text-sm">
                                {ug}
                            </div>
                        </div>

                        {/* Months Data Cells - TALLER BLOCKS */}
                        {availableMonths.map(month => {
                            const record = ugRecords.find(r => r.date === month && r.group === group);
                            const diff = record ? record.difference : 0;

                            return (
                                <div 
                                    key={month}
                                    className={`h-12 rounded flex items-center justify-center text-sm tracking-wide transition-all cursor-help
                                        ${getCellColor(diff, localMax)}
                                    `}
                                    title={record ? `${month}: R$ ${diff.toLocaleString('pt-BR')}` : 'Sem dados'}
                                >
                                    {formatCompact(diff)}
                                </div>
                            );
                        })}

                        {/* Action Column */}
                        <div className="flex justify-center h-12 items-center">
                             <button 
                                onClick={() => {
                                    const latest = ugRecords.filter(r => r.group === group).sort((a, b) => parseDateString(b.date).timestamp - parseDateString(a.date).timestamp)[0];
                                    if(latest) onSendMessage(latest);
                                }}
                                className="w-9 h-9 flex items-center justify-center rounded bg-slate-800 text-slate-400 hover:text-white hover:bg-blue-600 transition-colors border border-slate-700 shadow-sm"
                             >
                                 <MessageSquareText className="w-4 h-4" />
                             </button>
                        </div>
                    </div>
                   );
                });
              })}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import { FinancialRecord, RawInputRow, AccountGroup, TimeFilter } from '../types';

// Helper to safely parse dates in format "MONTH/YEAR" or "Mon/Year"
export const parseDateString = (dateStr: string): { month: number, year: number, timestamp: number } => {
  try {
    if (!dateStr) return { month: 0, year: 0, timestamp: 0 };

    const parts = dateStr.split('/');
    if (parts.length < 2) return { month: 0, year: 0, timestamp: 0 };

    const [monthStr, yearStr] = parts;
    const months: Record<string, number> = {
      'JANEIRO': 0, 'FEVEREIRO': 1, 'MARÇO': 2, 'ABRIL': 3, 'MAIO': 4, 'JUNHO': 5,
      'JULHO': 6, 'AGOSTO': 7, 'SETEMBRO': 8, 'OUTUBRO': 9, 'NOVEMBRO': 10, 'DEZEMBRO': 11,
      'JAN': 0, 'FEV': 1, 'MAR': 2, 'ABR': 3, 'MAI': 4, 'JUN': 5,
      'JUL': 6, 'AGO': 7, 'SET': 8, 'OUT': 9, 'NOV': 10, 'DEZ': 11
    };

    const cleanMonth = monthStr.trim().toUpperCase();
    const month = months[cleanMonth] !== undefined ? months[cleanMonth] : 0;
    const year = parseInt(yearStr) || new Date().getFullYear();

    return {
      month,
      year,
      timestamp: new Date(year, month, 1).getTime()
    };
  } catch (e) {
    console.error("Date Parse Error", e);
    return { month: 0, year: 0, timestamp: 0 };
  }
};

// --- DATA NORMALIZATION ---
export const normalizeData = (rawRows: RawInputRow[]): FinancialRecord[] => {
  const normalized: FinancialRecord[] = [];
  if (!rawRows || !Array.isArray(rawRows)) return [];

  rawRows.forEach((row, index) => {
    // Defensive check
    if (!row) return;

    const { month, year } = parseDateString(row.data);
    const safeCod = row.cod || '000000';
    const safeUg = row.ug || 'DESCONHECIDO';

    // Helper to process a group safely
    const processGroup = (groupEnum: AccountGroup, siafi: number, siloms: number, explicitDiff: number) => {
      // Logic: Use explicit diff if present (and logically valid), else calc
      const finalDiff = explicitDiff !== 0 ? Math.abs(explicitDiff) : Math.abs(siafi - siloms);

      let preponderance: 'SIAFI' | 'SILOMS' | 'EQUAL' = 'EQUAL';
      if (siafi > siloms) preponderance = 'SIAFI';
      if (siloms > siafi) preponderance = 'SILOMS';

      // Unique ID Generator: SAFE against duplicates
      // ID = COD + GROUP + TIMESTAMP + INDEX (to ensure uniqueness if rows duplicate)
      const uniqueId = `${safeCod}-${groupEnum}-${year}${month}-${index}`;

      normalized.push({
        id: uniqueId,
        date: row.data,
        monthIndex: month,
        year: year,
        cod: safeCod,
        ug: safeUg,
        group: groupEnum,
        siafiValue: siafi || 0,
        silomsValue: siloms || 0,
        difference: finalDiff || 0,
        preponderance,
        // Init optional fields
        previousDifference: 0,
        previousDate: '',
        delta: 0
      });
    };

    // STRICT GROUP MAPPING
    processGroup(AccountGroup.CONSUMO, row.g1_siafi, row.g1_siloms, row.g1_diff);
    processGroup(AccountGroup.BMP, row.g2_siafi, row.g2_siloms, row.g2_diff);
    processGroup(AccountGroup.INTANGIVEL, row.g3_siafi, row.g3_siloms, row.g3_diff);
  });

  return normalized;
};

// --- DELTA RECALCULATION BASED ON TIME FILTER ---
export const recalculateDeltas = (data: FinancialRecord[], timeFilter: TimeFilter): FinancialRecord[] => {
  // 1. Determine the gap in months based on filter
  let monthGap = 1; // Default MENSAL
  if (timeFilter === 'TRIMESTRAL') monthGap = 3;
  if (timeFilter === 'SEMESTRAL') monthGap = 6;
  if (timeFilter === 'ANUAL') monthGap = 12;

  return data.map(record => {
    // Calculate target previous date
    let targetMonth = record.monthIndex - monthGap;
    let targetYear = record.year;

    // Handle year rollover (simple implementation for typical gaps)
    while (targetMonth < 0) {
      targetMonth += 12;
      targetYear -= 1;
    }

    // Find the comparison record (Previous period)
    // We match by COD and GROUP. UG Name is ignored as it might have typos in history.
    const prevRecord = data.find(r => 
      r.cod === record.cod && 
      r.group === record.group && 
      r.monthIndex === targetMonth && 
      r.year === targetYear
    );

    const prevDiff = prevRecord ? prevRecord.difference : 0;
    const prevDate = prevRecord ? prevRecord.date : (monthGap > 1 ? `PERÍODO ANTERIOR (-${monthGap}m)` : 'MÊS ANTERIOR');

    // Delta = Current - Previous
    // Positive Delta = Difference Increased (Worsened)
    // Negative Delta = Difference Decreased (Improved)
    const delta = record.difference - prevDiff;

    return {
      ...record,
      previousDifference: prevDiff,
      previousDate: prevDate,
      delta
    };
  });
};

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
    maximumFractionDigits: 2,
    minimumFractionDigits: 2
  }).format(value || 0);
};

// --- MESSAGE GENERATOR WITH HISTORICAL ANALYSIS ---

interface TrendJump {
  found: boolean;
  fromMonth: string;
  toMonth: string;
  fromValue: number;
  toValue: number;
}

// Analyze history to find the first moment where a relevant increase occurred and persisted
const findPersistentJump = (history: FinancialRecord[]): TrendJump => {
  // 1. Sort history chronologically
  const sorted = [...history].sort((a, b) => 
    (a.year * 100 + a.monthIndex) - (b.year * 100 + b.monthIndex)
  );

  if (sorted.length < 2) return { found: false, fromMonth: '', toMonth: '', fromValue: 0, toValue: 0 };

  // 2. Iterate to find the "Jump"
  // A jump is defined as:
  // a) Increase > 10% (relative) or huge absolute value
  // b) Subsequent values roughly maintain that level (don't drop back to pre-jump levels)

  for (let i = 1; i < sorted.length; i++) {
    const prev = sorted[i-1];
    const curr = sorted[i];

    // Check for increase
    if (curr.difference > prev.difference) {
       const delta = curr.difference - prev.difference;
       const pctChange = prev.difference > 0 ? (delta / prev.difference) : 1; // 100% if prev was 0

       // Threshold: Significant increase (e.g., > R$ 50k and > 5% increase, OR just a huge jump)
       const isSignificant = (delta > 50000 && pctChange > 0.05);

       if (isSignificant) {
         // Check persistence: Look ahead
         // Does it stay high? (Average of future values >= current value * 0.9)
         const futureRecords = sorted.slice(i + 1);
         if (futureRecords.length === 0) {
            // It happened in the very last month, so it is a jump
            return {
              found: true,
              fromMonth: prev.date,
              toMonth: curr.date,
              fromValue: prev.difference,
              toValue: curr.difference
            };
         }

         const futureAvg = futureRecords.reduce((sum, r) => sum + r.difference, 0) / futureRecords.length;

         // If future average stays roughly at the new high level (or higher)
         if (futureAvg >= curr.difference * 0.85) {
            return {
              found: true,
              fromMonth: prev.date,
              toMonth: curr.date,
              fromValue: prev.difference,
              toValue: curr.difference
            };
         }
       }
    }
  }

  return { found: false, fromMonth: '', toMonth: '', fromValue: 0, toValue: 0 };
};

export const generateSiafiMessageText = (record: FinancialRecord, msgNumber: string, deadline: string, history?: FinancialRecord[]): string => {
  try {
    if (!record) throw new Error("Registro inválido para geração de mensagem.");

    const today = new Date();
    const dateStr = today.toLocaleDateString('pt-BR');
    const timeStr = today.toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'});

    const currentShortDate = record.date.toUpperCase(); 

    // Friendly Group Name
    const groupMap: Record<string, string> = {
      [AccountGroup.CONSUMO]: "BENS DE CONSUMO",
      [AccountGroup.BMP]: "BENS MÓVEIS PERMANENTES",
      [AccountGroup.INTANGIVEL]: "BENS INTANGÍVEIS"
    };
    const groupText = groupMap[record.group] || "CONTA EM ANÁLISE";
    const groupTextLower = groupText.toLowerCase();

    const separator = "--------------------------------------------------";

    // --- HISTORICAL ANALYSIS ---
    let analysisBlock = "";
    let evolutionTable = "";

    if (history && history.length > 0) {
       // 1. Sort for display
       const sortedHistory = [...history].sort((a, b) => (a.year * 100 + a.monthIndex) - (b.year * 100 + b.monthIndex));

       // 2. Find Jump
       const jump = findPersistentJump(sortedHistory);

       if (jump.found) {
         analysisBlock = `
PONTO DE ATENÇÃO:
Identificou-se que a divergência evoluiu de ${formatCurrency(jump.fromValue)} (${jump.fromMonth}) para ${formatCurrency(jump.toValue)} em ${jump.toMonth}, chegando ao saldo atual de ${formatCurrency(record.difference)}. A persistência do valor elevado desde ${jump.toMonth} requer atenção.

Diante do exposto, solicita-se a análise pormenorizada dos lançamentos ocorridos a partir de ${jump.toMonth}, visando identificar a causa raiz da distorção.`;
       } else {
         // Fallback if no specific jump found (steady growth or fluctuation)
         analysisBlock = `
PONTO DE ATENÇÃO:
Verificou-se que a divergência mantém um patamar elevado, totalizando atualmente ${formatCurrency(record.difference)}. Solicita-se a análise da composição deste saldo.`;
       }

       // 3. Build Evolution Table
       evolutionTable = `
DETALHAMENTO MÊS A MÊS:
DATA       | SIAFI           | SILOMS          | DIFERENÇA
${sortedHistory.map(h => {
  const d = h.date.split('/')[0].substring(0,3) + '/' + h.date.split('/')[1].substring(2,4); // JAN/25
  const s = h.siafiValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(14, ' ');
  const m = h.silomsValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(14, ' ');
  const diff = h.difference.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(14, ' ');
  return `${d.padEnd(10)} | ${s} | ${m} | ${diff}`;
}).join('\n')}
`;
    }

    // --- TEMPLATE ASSEMBLY ---
    return `${today.getFullYear()}/xxxxxxx Regularização Contábil - ${record.ug} - ${groupText}

Remetente: xxxxx - SETORIAL DE CONTABILIDADE
Enviado em: ${dateStr} às ${timeStr}
UG destinatária: ${record.cod} ${record.ug}

AG DA ADMINISTRAÇÃO: Ordenador de Despesas, Agente de Controle Interno, Gestor de Almoxarifado e demais gestores envolvidos.

MSG NR ${msgNumber || 'XXX'}/SUCONT-4/${today.toLocaleDateString('pt-BR').replace(/\//g, '')}.

Em análise da matriz histórica de diferenças desta UG, identificou-se um comportamento atípico nas contas de ${groupTextLower}.

${analysisBlock}

${evolutionTable}

${separator}
SISTEMA PREPONDERANTE (MAIOR SALDO): ${record.preponderance}
${separator}

Conclusão:
Diante do exposto, solicita-se ao gestor responsável que providencie a equalização das diferenças até o dia ${deadline || '[PRAZO]'}, considerando o fechamento mensal. Solicita-se, ainda, que seja encaminhada resposta via SAU, apresentando justificativa fundamentada quanto às diferenças identificadas e cronograma de saneamento.

Esta Diretoria reconhece o trabalho realizado pela gestão da Unidade e coloca à disposição a Divisão de Acompanhamento Patrimonial para interações julgadas oportunas.

DIREF/SUCONT/SUCONT-4
`;
  } catch (error) {
    console.error("Error generating message:", error);
    return "ERRO AO GERAR MENSAGEM. VERIFIQUE OS DADOS DO REGISTRO.";
  }
};

