export const EvolutionChart: React.FC<ChartProps> = ({ data, isDarkMode }) => {
  if (!data) return null;

  const timeSeries = data.reduce((acc, curr) => {
    const found = acc.find(item => item.date === curr.date);
    if (found) {
      found.totalDiff += curr.difference;
      found.totalSiafi += curr.siafiValue; // Accumulate for tooltip
      found.totalSiloms += curr.silomsValue; // Accumulate for tooltip
    } else {
      acc.push({ 
        date: curr.date, 
        totalDiff: curr.difference, 
        totalSiafi: curr.siafiValue,
        totalSiloms: curr.silomsValue,
        timestamp: (curr.year * 100) + curr.monthIndex,
        // Helper to format date for axis
        axisLabel: `${curr.date.split('/')[0].substring(0,3)}/${curr.date.split('/')[1].substring(2,4)}`
      });
    }
    return acc;
  }, [] as { date: string, totalDiff: number, totalSiafi: number, totalSiloms: number, timestamp: number, axisLabel: string }[]);

  timeSeries.sort((a, b) => a.timestamp - b.timestamp);

  if (timeSeries.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  return (
    <div className="w-full h-full min-h-[250px]">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={timeSeries} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          <defs>
