// 2. HEATMAP MESSAGE (Historical Trend)
const generateHeatmapMessage = (record: FinancialRecord, msgNumber: string, deadline: string, history: FinancialRecord[]): string => {
    const today = new Date();
    const dateStr = today.toLocaleDateString('pt-BR');
    const timeStr = today.toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'});
    const groupText = getFriendlyGroupName(record.group);
    const separator = "--------------------------------------------------";

    // Sort history chronologically
    const sortedHistory = [...history].sort((a, b) => 
        (a.year * 100 + a.monthIndex) - (b.year * 100 + b.monthIndex)
    );

    let analysisBlock = "";

    // Find the inflection point (Jump)
    // We look for a point where the difference was significantly lower, then jumped and stayed high/increased to current
    let jumpStart: FinancialRecord | null = null;
    let jumpEnd: FinancialRecord | null = null;

    // Filter history to records *before* current (or including current)
    const relevantHistory = sortedHistory.filter(h => (h.year * 100 + h.monthIndex) <= (record.year * 100 + record.monthIndex));

    // Work backwards from current to find where it "started" being high
    // We assume "High" is > 70% of current value. 
    // The "Jump" is the transition from < 70% to > 70%.

    if (relevantHistory.length >= 2) {
        for (let i = relevantHistory.length - 1; i > 0; i--) {
            const curr = relevantHistory[i];
            const prev = relevantHistory[i-1];

            // Logic: If current is high (close to record val) and prev was significantly lower (e.g., < 50% or < 80% depending on sensitivity)
            // Let's use: A significant jump is defined as prev being < 60% of current record diff
            if (prev.difference < (record.difference * 0.6)) {
                jumpStart = prev; // The month "from"
                jumpEnd = curr;   // The month "to"
                break; // Found the most recent major jump
            }
        }
    }

    if (jumpStart && jumpEnd) {
        analysisBlock = `
PONTO DE ATENÇÃO:
Identificou-se que a divergência evoluiu de ${formatCurrency(jumpStart.difference)} em ${jumpStart.date} para ${formatCurrency(jumpEnd.difference)} em ${jumpEnd.date}, chegando ao saldo atual de ${formatCurrency(record.difference)} em ${record.date}. A persistência do valor elevado desde ${jumpEnd.date} requer atenção.

Diante do exposto, solicita-se a análise pormenorizada dos lançamentos ocorridos a partir de ${jumpStart.date}, visando identificar a causa raiz da distorção.`;
    } else {
        // Fallback if no specific sharp jump found (maybe it was always high, or gradual)
        // Try to find the start of the year or oldest record
        const startRecord = relevantHistory[0];
        analysisBlock = `
PONTO DE ATENÇÃO:
Identificou-se que a divergência vem evoluindo desde ${startRecord.date} (${formatCurrency(startRecord.difference)}), chegando ao saldo atual de ${formatCurrency(record.difference)} em ${record.date}.

Diante do exposto, solicita-se a análise pormenorizada dos lançamentos para identificar a causa raiz da distorção.`;
    }

    const evolutionTable = `
DETALHAMENTO MÊS A MÊS:
DATA       | SIAFI           | SILOMS          | DIFERENÇA
${sortedHistory.map(h => {
  const d = h.date.split('/')[0].substring(0,3) + '/' + h.date.split('/')[1].substring(2,4); 
  const s = h.siafiValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(14, ' ');
  const m = h.silomsValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(14, ' ');
  const diff = h.difference.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(14, ' ');
  return `${d.padEnd(10)} | ${s} | ${m} | ${diff}`;
}).join('\n')}
`;

    return `${today.getFullYear()}/xxxxxxx Regularização Contábil - ${record.ug} - ${groupText}

Remetente: xxxxx - SETORIAL DE CONTABILIDADE
Enviado em: ${dateStr} às ${timeStr}
UG destinatária: ${record.cod} ${record.ug}

AG DA ADMINISTRAÇÃO: Ordenador de Despesas, Agente de Controle Interno, Gestor de Almoxarifado e demais gestores envolvidos.

MSG NR ${msgNumber || 'XXX'}/SUCONT-4/${today.toLocaleDateString('pt-BR').replace(/\//g, '')}.

Em análise da matriz histórica de diferenças desta UG, identificou-se um comportamento atípico nas contas de ${groupText.toLowerCase()}.

${analysisBlock}

${evolutionTable}

${separator}
SISTEMA PREPONDERANTE (MAIOR SALDO): ${record.preponderance}
${separator}

Conclusão:
Diante do exposto, solicita-se ao gestor responsável que providencie a equalização das diferenças até o dia ${deadline || '[PRAZO]'}, considerando o fechamento mensal. Solicita-se, ainda, que seja encaminhada resposta via SAU, apresentando justificativa fundamentada quanto às diferenças identificadas e cronograma de saneamento.

Esta Diretoria reconhece o trabalho realizado pela gestão da Unidade e coloca à disposição a Divisão de Acompanhamento Patrimonial para interações julgadas oportunas.

DIREF/SUCONT/SUCONT-4`;
