        (a.year * 100 + a.monthIndex) - (b.year * 100 + b.monthIndex)
    );

    let analysisBlock = "";

    // Find the inflection point (Jump)
    let jumpStart: FinancialRecord | null = null;
    let jumpEnd: FinancialRecord | null = null;

    const relevantHistory = sortedHistory.filter(h => (h.year * 100 + h.monthIndex) <= (record.year * 100 + record.monthIndex));

    if (relevantHistory.length >= 2) {
        for (let i = relevantHistory.length - 1; i > 0; i--) {
            const curr = relevantHistory[i];
            const prev = relevantHistory[i-1];

            // Logic: A significant jump is defined as prev being < 60% of current record diff
            if (prev.difference < (record.difference * 0.6)) {
