              />
              <StatCard 
                title="Saldo SIAFI" value={formatCurrency(stats.totalSiafi)} 
                subtitle="Contábil (Completo)" icon={LayoutDashboard} colorClass="text-blue-500" bgClass="bg-blue-500" 
              />
              <StatCard 
                title="Saldo SILOMS" value={formatCurrency(stats.totalSiloms)} 
                subtitle="Físico (Completo)" icon={Layers} colorClass="text-emerald-500" bgClass="bg-emerald-500" 
