              className="h-[500px]"
              allData={filteredDataForVisuals} // Passing visual data (may hide zeros)
              availableMonths={uniqueMonths}
              availableUGs={uniqueUGs}
              isDarkMode={isDarkMode}
              defaultMonth={selectedMonth}
              defaultGroup={selectedGroup}
            >
              {(data) => <RankingList 
