    const padDate = (d: string) => d.padEnd(10, ' ');

    // Construct Table
    const headerRow = "DATA       | SIAFI           | SILOMS          | DIFERENÇA";
    const prevRow   = `${padDate(prevLabel)} | ${fmt(record.previousSiafiValue || 0)} | ${fmt(record.previousSilomsValue || 0)} | ${fmt(record.previousDifference || 0)}`;
    const currRow   = `${padDate(currLabel)} | ${fmt(record.siafiValue)} | ${fmt(record.silomsValue)} | ${fmt(record.difference)}`;

    const table = `${headerRow}\n${prevRow}\n${currRow}`;

    return `${today.getFullYear()}/xxxxxxx Incompatibilidade de saldos nas contas de ${groupText.toLowerCase()} - ${currLabel}

Remetente: xxxxx - SETORIAL DE CONTABILIDADE
Enviado em: ${dateStr} às ${timeStr}
UG destinatárias: ${record.cod} ${record.ug}
Mensagem:

AG DA ADMINISTRAÇÃO: Ordenador de Despesas, Agente de Controle Interno, Gestor de Almoxarifado e demais gestores envolvidos.

MSG NR ${msgNumber || 'XXX'}/SUCONT-4/${today.toLocaleDateString('pt-BR').replace(/\//g, '')}.

Conforme verificação realizada por esta Setorial na data de hoje, informo que essa UG está com divergência significativa de saldos entre os sistemas SIAFI e SILOMS nas contas de ${groupText.toLowerCase()}, conforme detalhado abaixo:

--------------------------------------------------
EVOLUÇÃO DO SALDO E DIVERGÊNCIA (SIAFI X SILOMS)
--------------------------------------------------
${table}
--------------------------------------------------
${variationLabel.padEnd(21)}:   ${formatCurrency(increase)}
--------------------------------------------------

Diante do exposto, solicita-se ao gestor responsável que providencie a equalização das diferenças até o dia ${deadline || '[PRAZO]'}, considerando o fechamento mensal. Solicita-se, ainda, que seja encaminhada resposta via SAU, apresentando justificativa quanto às diferenças identificadas.

Por fim, coloco à disposição a Divisão de Acompanhamento Patrimonial para interações julgadas oportunas sobre este assunto.

DIREF/SUCONT/SUCONT-4`;
};

// 2. HEATMAP MESSAGE (Historical Trend Analysis)
// Ignores the "Filter" and looks at the historical timeline to find the jump.
const generateHeatmapMessage = (record: FinancialRecord, msgNumber: string, deadline: string, history: FinancialRecord[]): string => {
    const today = new Date();
    const dateStr = today.toLocaleDateString('pt-BR');
    const timeStr = today.toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'});
    const groupText = getFriendlyGroupName(record.group);
    const separator = "--------------------------------------------------";

    // Sort history chronologically
    const sortedHistory = [...history].sort((a, b) => 
        (a.year * 100 + a.monthIndex) - (b.year * 100 + b.monthIndex)
    );

    // Filter to current and past
    const relevantHistory = sortedHistory.filter(h => (h.year * 100 + h.monthIndex) <= (record.year * 100 + record.monthIndex));

    let analysisBlock = "";

    // --- JUMP ANALYSIS LOGIC ---
    let jumpStart = relevantHistory[0]; // Default: Start of history
    let jumpEnd = relevantHistory[relevantHistory.length - 1]; // Default: Current
    let foundJump = false;

    if (relevantHistory.length >= 2) {
        const highThreshold = record.difference * 0.8; 
        let lowIndex = -1;

        for (let i = relevantHistory.length - 1; i >= 0; i--) {
             if (relevantHistory[i].difference < highThreshold) {
                 lowIndex = i;
                 break; // Found the low point closest to now
             }
        }

        if (lowIndex !== -1 && lowIndex < relevantHistory.length - 1) {
             jumpStart = relevantHistory[lowIndex];       // The month it was low
             jumpEnd = relevantHistory[lowIndex + 1];     // The month it jumped (Start of persistence)
             foundJump = true;
        } else {
             jumpStart = relevantHistory[0];
             jumpEnd = relevantHistory[0]; 
        }
    }

    const startD = toShortDate(jumpStart.date);
    const endD = toShortDate(jumpEnd.date); // This is "Persistence since..."
    const currD = toShortDate(record.date);

    if (foundJump) {
        analysisBlock = `
PONTO DE ATENÇÃO:
Identificou-se que a divergência evoluiu de ${formatCurrency(jumpStart.difference)} em ${startD}, chegando ao saldo atual de ${formatCurrency(record.difference)} em ${currD}. A persistência do valor elevado desde ${endD} requer atenção.

Diante do exposto, solicita-se a análise pormenorizada dos lançamentos ocorridos a partir de ${startD}, visando identificar a causa raiz da distorção.`;
    } else {
        // Fallback if no specific jump (e.g. consistent increase)
        analysisBlock = `
PONTO DE ATENÇÃO:
Identificou-se que a divergência vem evoluindo desde ${startD} (${formatCurrency(jumpStart.difference)}), chegando ao saldo atual de ${formatCurrency(record.difference)} em ${currD}.

Diante do exposto, solicita-se a análise pormenorizada dos lançamentos para identificar a causa raiz da distorção.`;
    }

    const evolutionTable = `
DETALHAMENTO MÊS A MÊS:
DATA       | SIAFI           | SILOMS          | DIFERENÇA
${sortedHistory.map(h => {
  const d = toShortDate(h.date); 
  const s = h.siafiValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(15, ' ');
  const m = h.silomsValue.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(15, ' ');
  const diff = h.difference.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).padStart(15, ' ');
  return `${d.padEnd(10)} | ${s} | ${m} | ${diff}`;
}).join('\n')}
`;

    return `${today.getFullYear()}/xxxxxxx Regularização Contábil - ${record.ug} - ${groupText}

Remetente: xxxxx - SETORIAL DE CONTABILIDADE
Enviado em: ${dateStr} às ${timeStr}
UG destinatária: ${record.cod} ${record.ug}

AG DA ADMINISTRAÇÃO: Ordenador de Despesas, Agente de Controle Interno, Gestor de Almoxarifado e demais gestores envolvidos.

MSG NR ${msgNumber || 'XXX'}/SUCONT-4/${today.toLocaleDateString('pt-BR').replace(/\//g, '')}.

Em análise da matriz histórica de diferenças desta UG, identificou-se um comportamento atípico nas contas de ${groupText.toLowerCase()}.

${analysisBlock}

${evolutionTable}

${separator}
SISTEMA PREPONDERANTE (MAIOR SALDO): ${record.preponderance}
${separator}

Conclusão:
Diante do exposto, solicita-se ao gestor responsável que providencie a equalização das diferenças até o dia ${deadline || '[PRAZO]'}, considerando o fechamento mensal. Solicita-se, ainda, que seja encaminhada resposta via SAU, apresentando justificativa fundamentada quanto às diferenças identificadas e cronograma de saneamento.

Esta Diretoria reconhece o trabalho realizado pela gestão da Unidade e coloca à disposição a Divisão de Acompanhamento Patrimonial para interações julgadas oportunas.

DIREF/SUCONT/SUCONT-4`;
};


// --- MAIN EXPORT ---
export const generateMessage = (
    type: 'RANKING' | 'HEATMAP', 
    record: FinancialRecord, 
    msgNumber: string, 
    deadline: string, 
    history: FinancialRecord[] = []
): string => {
    try {
        if (type === 'RANKING') {
            return generateRankingMessage(record, msgNumber, deadline);
        } else {
            return generateHeatmapMessage(record, msgNumber, deadline, history);
        }
    } catch (error) {
        console.error("Error generating message:", error);
        return "ERRO AO GERAR MENSAGEM. VERIFIQUE OS DADOS.";
    }
};

// Kept for backward compatibility if needed, but aliased to Heatmap style default
export const generateSiafiMessageText = (record: FinancialRecord, msgNumber: string, deadline: string, history?: FinancialRecord[]) => 
    generateHeatmapMessage(record, msgNumber, deadline, history || []);

import React, { useState, useRef, useEffect } from 'react';
import { ChevronDown, Check } from 'lucide-react';

interface Option {
  value: string;
  label: string;
}

interface CustomSelectProps {
  value: string;
  onChange: (value: string) => void;
  options: Option[];
  placeholder?: string;
  className?: string;
}

export const CustomSelect: React.FC<CustomSelectProps> = ({ 
  value, 
  onChange, 
  options, 
  placeholder = "Selecione...",
  className = ""
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const selectedOption = options.find(opt => opt.value === value);

  // Click outside to close
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className={`relative ${className}`} ref={containerRef}>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={`w-full flex items-center justify-between px-3 py-2 text-xs sm:text-sm font-medium rounded-lg border transition-all
          bg-white dark:bg-slate-800 
          border-slate-200 dark:border-slate-700 
          text-slate-700 dark:text-slate-200 
          hover:border-slate-400 dark:hover:border-slate-500 
          hover:bg-slate-50 dark:hover:bg-slate-750
          focus:ring-2 focus:ring-blue-500/50
          ${isOpen ? 'ring-2 ring-blue-500/50 border-blue-500' : ''}
        `}
      >
        <span className="truncate mr-2">
          {selectedOption ? selectedOption.label : placeholder}
        </span>
        <ChevronDown className={`w-4 h-4 text-slate-500 dark:text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-1 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg shadow-xl max-h-60 overflow-y-auto custom-scrollbar animate-in fade-in zoom-in-95 duration-100">
          <div className="py-1">
            {options.map((option) => (
              <button
                key={option.value}
                onClick={() => {
                  onChange(option.value);
                  setIsOpen(false);
                }}
                className={`w-full text-left px-3 py-2 text-xs sm:text-sm flex items-center justify-between transition-colors
                  ${option.value === value 
                    ? 'bg-blue-50 dark:bg-blue-600/20 text-blue-600 dark:text-blue-400 font-semibold' 
                    : 'text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700'
                  }
                `}
              >
                <span className="truncate">{option.label}</span>
                {option.value === value && <Check className="w-3 h-3 ml-2" />}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
