import React, { useState, useMemo } from 'react';
import { MessageSquareText, ArrowUpDown } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';
import { parseDateString } from '../services/dataProcessor';

interface TemporalHeatmapProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  availableMonths: string[];
  onSendMessage: (record: FinancialRecord, context?: 'RANKING' | 'HEATMAP') => void;
}

export const TemporalHeatmap: React.FC<TemporalHeatmapProps> = ({ 
  data, 
  isDarkMode, 
  availableMonths, 
  onSendMessage
}) => {
  const [internalGroupFilter, setInternalGroupFilter] = useState<string>('ALL');

  // Filter Data
  const filteredData = useMemo(() => data.filter(item => 
    internalGroupFilter === 'ALL' || item.group === internalGroupFilter
  ), [data, internalGroupFilter]);

  // --- GLOBAL MAX FOR SMOOTH GRADIENT ---
  // Find the absolute largest difference across ALL displayed cells to normalize the gradient
  const globalMax = useMemo(() => {
    if (filteredData.length === 0) return 1;
    return Math.max(...filteredData.map(d => d.difference));
  }, [filteredData]);

  // --- CONTINUOUS HSL GRADIENT CALCULATOR ---
  const getCellStyles = (value: number, max: number, isDark: boolean) => {
    if (value === 0) {
      return {
        style: isDark 
          ? { backgroundColor: 'rgba(30, 41, 59, 0.4)', borderColor: 'rgba(30, 41, 59, 0.5)' } 
          : { backgroundColor: '#f8fafc', borderColor: '#e2e8f0' },
        className: isDark ? 'text-slate-600' : 'text-slate-300'
      };
    }

    // 1. Calculate Ratio (0 to 1)
    const ratio = max > 0 ? value / max : 0;

    // 2. Apply Sensitivity Curve (Square Root)
    // This makes smaller values more visible (visual boost)
    const adjustedRatio = Math.pow(ratio, 0.5);

    // 3. Calculate Hue (120 = Green, 60 = Yellow, 0 = Red)
    // We map 0 -> 120 and 1 -> 0
    const hue = Math.max(0, (1 - adjustedRatio) * 120);

    // 4. Calculate Lightness based on Theme
    let lightness: number;
    let borderColor: string;

    if (isDark) {
       // Dark Mode: Keep lightness low (20% - 30%) so it looks "Neon" on dark bg
       // As value increases (redder), slightly increase lightness for glow
       lightness = 20 + (adjustedRatio * 10); 
       borderColor = `hsl(${hue}, 90%, ${lightness + 10}%)`;
    } else {
       // Light Mode: Keep lightness high (95% - 85%) for pastel look
       // Border is darker
       lightness = 95 - (adjustedRatio * 15);
       borderColor = `hsl(${hue}, 70%, ${lightness - 30}%)`;
    }

    return {
      style: {
        backgroundColor: `hsl(${hue}, 85%, ${lightness}%)`,
        borderColor: borderColor,
        color: isDark ? '#fff' : '#1e293b' // High contrast text
      },
      className: 'font-bold shadow-sm'
    };
  };

  // Compact Number Formatter (399.3M, 931k)
  const formatCompact = (val: number) => {
    if (val === 0) return '-';
    if (val >= 1000000) return `${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `${(val / 1000).toFixed(0)}k`;
    return val.toFixed(0);
  };

  // Group Badge Color Helper (Updated to Red/Blue/Green as requested)
  const getGroupBadgeClass = (group: string) => {
    if (group === AccountGroup.BMP) 
      return 'bg-red-50 dark:bg-red-500/20 text-red-600 dark:text-red-400 border-red-200 dark:border-red-500/30 border shadow-sm dark:shadow-[0_0_5px_rgba(239,68,68,0.2)]';
    if (group === AccountGroup.CONSUMO) 
      return 'bg-blue-50 dark:bg-blue-500/20 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-500/30 border shadow-sm dark:shadow-[0_0_5px_rgba(59,130,246,0.2)]';
    if (group === AccountGroup.INTANGIVEL) 
      return 'bg-emerald-50 dark:bg-emerald-500/20 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-500/30 border shadow-sm dark:shadow-[0_0_5px_rgba(16,185,129,0.2)]';

    return 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300';
  };

  // Sort logic: Total Difference across all visible months
  const sortedUGs = useMemo(() => {
    const ugs = Array.from(new Set(filteredData.map(d => d.ug))) as string[];
    return ugs.sort((a, b) => {
      const sumA = filteredData.filter(r => r.ug === a).reduce((acc, r) => acc + r.difference, 0);
      const sumB = filteredData.filter(r => r.ug === b).reduce((acc, r) => acc + r.difference, 0);
      return sumB - sumA;
    });
  }, [filteredData]);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden text-xs bg-white dark:bg-[#0f172a] rounded-lg border border-slate-200 dark:border-slate-700">

      {/* Header Controls */}
      <div className="flex items-center justify-between gap-2 p-3 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800">
        <div className="flex items-center gap-2 overflow-x-auto">
           {[
               { id: 'ALL', label: 'TODOS', activeClass: 'text-slate-100 bg-slate-700 dark:bg-slate-600' },
               { id: AccountGroup.BMP, label: 'BMP', activeClass: 'text-white bg-red-500 border-red-500' },
               { id: AccountGroup.CONSUMO, label: 'CONSUMO', activeClass: 'text-white bg-blue-500 border-blue-500' },
               { id: AccountGroup.INTANGIVEL, label: 'INTANGIVEL', activeClass: 'text-white bg-emerald-500 border-emerald-500' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setInternalGroupFilter(tab.id)}
                className={`px-4 py-1.5 rounded text-xs font-bold uppercase transition-all whitespace-nowrap border border-transparent
                  ${internalGroupFilter === tab.id 
                    ? tab.activeClass 
                    : 'bg-white dark:bg-slate-900 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 border-slate-300 dark:border-slate-600'
                  }
                `}
              >
                {tab.label}
              </button>
            ))}
        </div>

        <div className="hidden sm:flex items-center gap-1 px-3 py-1.5 rounded bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-500 dark:text-slate-400 text-xs font-bold uppercase">
           <ArrowUpDown className="w-3 h-3" />
           Maior Valor
        </div>
      </div>

      {sortedUGs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-2">
            <span className="text-lg">Sem dados para exibir</span>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-white dark:bg-[#0f172a] relative">
          <div className="w-full min-w-[900px] p-3">

            {/* 
               GRID LAYOUT DEFINITION - EXPANDED
               Col 1: 180px fixed (Name)
               Col 2: Auto-fit (Months) - minmax(100px, 1fr) for wider columns
               Col 3: 50px fixed (Action)
            */}
            <div 
              className="grid gap-1 mb-2 sticky top-0 z-10 bg-white dark:bg-[#0f172a] pb-2 border-b border-slate-200 dark:border-slate-800 items-end"
              style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(100px, 1fr)) 50px` }}
            >
                <div className="text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider pl-2 text-xs">UG / GRUPO</div>

                {availableMonths.map(month => (
                    <div key={month} className="text-center text-slate-500 dark:text-slate-400 font-bold uppercase text-xs truncate px-1">
                        {month.split('/')[0].substring(0, 3)}/{month.split('/')[1].substring(2,4)}
                    </div>
                ))}

                <div className="text-center text-slate-500 dark:text-slate-400 font-bold text-xs">MSG</div>
            </div>

            {/* Rows - EXPANDED HEIGHT (h-12) */}
            <div className="space-y-1.5">
              {sortedUGs.map(ug => {
                const ugRecords = filteredData.filter(d => d.ug === ug);
                const uniqueGroups = (Array.from(new Set(ugRecords.map(r => r.group))) as AccountGroup[]).sort();

                return uniqueGroups.map(group => {

                   return (
                    <div 
                        key={`${ug}-${group}`} 
                        className="grid gap-1 items-center hover:bg-slate-50 dark:hover:bg-slate-800/30 rounded transition-colors"
                        style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(100px, 1fr)) 50px` }}
                    >

                        {/* Name Column */}
                        <div className="flex items-center h-12 overflow-hidden rounded bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700/50">
                            <div className={`w-10 h-full flex items-center justify-center text-[9px] font-black uppercase ${getGroupBadgeClass(group)}`}>
                                {group === AccountGroup.BMP ? 'BMP' : group === AccountGroup.CONSUMO ? 'CN' : 'INT'}
                            </div>
                            <div className="flex-1 px-3 text-slate-700 dark:text-slate-200 font-bold truncate text-sm">
                                {ug}
                            </div>
                        </div>

                        {/* Months Data Cells - CONTINUOUS GRADIENT */}
                        {availableMonths.map(month => {
                            const record = ugRecords.find(r => r.date === month && r.group === group);
                            const diff = record ? record.difference : 0;
                            const { style, className } = getCellStyles(diff, globalMax, isDarkMode);

                            return (
                                <div 
                                    key={month}
                                    style={style} // Apply dynamic HSL gradient
                                    className={`h-12 rounded flex items-center justify-center text-[11px] tracking-wide transition-all cursor-help border ${className}`}
                                    title={record ? `${month}: R$ ${diff.toLocaleString('pt-BR')}` : 'Sem dados'}
                                >
                                    {formatCompact(diff)}
                                </div>
                            );
                        })}

                        {/* Action Column */}
                        <div className="flex justify-center h-12 items-center">
                             <button 
                                onClick={() => {
                                    const latest = ugRecords.filter(r => r.group === group).sort((a, b) => parseDateString(b.date).timestamp - parseDateString(a.date).timestamp)[0];
                                    if(latest) onSendMessage(latest, 'HEATMAP');
                                }}
                                className="w-9 h-9 flex items-center justify-center rounded bg-white dark:bg-slate-800 text-slate-400 hover:text-white hover:bg-blue-600 transition-colors border border-slate-200 dark:border-slate-700 shadow-sm"
                             >
                                 <MessageSquareText className="w-4 h-4" />
                             </button>
                        </div>
                    </div>
                   );
                });
              })}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Copy, Check, Calendar, Hash, MessageSquareText } from 'lucide-react';
import { FinancialRecord } from '../types';
import { generateMessage } from '../services/dataProcessor';

interface SiafiMessageModalProps {
  isOpen: boolean;
  onClose: () => void;
  record: FinancialRecord | null;
  history?: FinancialRecord[]; 
  context?: 'RANKING' | 'HEATMAP'; // Added context
}

export const SiafiMessageModal: React.FC<SiafiMessageModalProps> = ({ isOpen, onClose, record, history, context = 'HEATMAP' }) => {
  const [msgNumber, setMsgNumber] = useState('XXX');
  const [deadline, setDeadline] = useState('');
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    if (isOpen) {
      // Set default deadline to 3 days from now
      const date = new Date();
      date.setDate(date.getDate() + 3);
      setDeadline(date.toLocaleDateString('pt-BR'));
      setCopied(false);
    }
  }, [isOpen]);

  if (!isOpen || !record) return null;

  const messageText = generateMessage(context as 'RANKING' | 'HEATMAP', record, msgNumber, deadline, history);

  const handleCopy = () => {
    navigator.clipboard.writeText(messageText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="w-full max-w-5xl bg-white dark:bg-[#1e293b] border border-slate-200 dark:border-slate-700 rounded-xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">

        {/* Header */}
        <div className="p-5 border-b border-slate-200 dark:border-slate-700 flex items-center justify-between bg-slate-50 dark:bg-[#0f172a]">
          <div className="flex items-center gap-3">
            <MessageSquareText className="w-6 h-6 text-blue-600 dark:text-blue-500" />
