// --- Evolution Area Chart (Improved with Brush for 1-year default window) ---

export const EvolutionChart: React.FC<ChartProps> = ({ data, isDarkMode }) => {
  if (!data) return null;

  const timeSeries = data.reduce((acc, curr) => {
    const found = acc.find(item => item.date === curr.date);
    if (found) {
      found.totalDiff += curr.difference;
      found.totalSiafi += curr.siafiValue; // Accumulate for tooltip
      found.totalSiloms += curr.silomsValue; // Accumulate for tooltip
    } else {
      acc.push({ 
        date: curr.date, 
        totalDiff: curr.difference, 
        totalSiafi: curr.siafiValue,
        totalSiloms: curr.silomsValue,
        timestamp: (curr.year * 100) + curr.monthIndex,
        // Helper to format date for axis
        axisLabel: `${curr.date.split('/')[0].substring(0,3)}/${curr.date.split('/')[1].substring(2,4)}`
      });
    }
    return acc;
  }, [] as { date: string, totalDiff: number, totalSiafi: number, totalSiloms: number, timestamp: number, axisLabel: string }[]);

  timeSeries.sort((a, b) => a.timestamp - b.timestamp);

  if (timeSeries.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  // Calculate default range indices: 12 months back from the end
  const totalPoints = timeSeries.length;
  // If we have more than 12 points, start at length - 12 (showing last 12). Otherwise start at 0.
  // Using 11 to include current month (0 to 11 is 12 items)
  const startIndex = Math.max(0, totalPoints - 12);
  const endIndex = Math.max(0, totalPoints - 1);

  return (
    <div className="w-full h-full min-h-[250px]">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={timeSeries} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
          <defs>
            <linearGradient id="colorDiff" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#6366f1" stopOpacity={0.8}/>
              <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e2e8f0'} />
          <XAxis 
            dataKey="axisLabel" 
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false} 
          />
          <YAxis 
            tickFormatter={(value) => `${(value / 1000000).toFixed(0)}M`} 
            tick={{fill: isDarkMode ? '#94a3b8' : '#64748b'}} 
            axisLine={false} 
            tickLine={false}
          />
          {/* We pass all data to tooltip via the payload of the area */}
          <Tooltip content={<CustomDetailedTooltip isDarkMode={isDarkMode} />} />
          <Area 
            type="monotone" 
            dataKey="totalDiff" 
            name="Diferença Total" 
            stroke="#6366f1" 
            fillOpacity={1} 
            fill="url(#colorDiff)" 
            strokeWidth={3}
          />
          {/* Added Brush Component for Range Selection */}
          <Brush 
            dataKey="axisLabel" 
            height={30} 
            stroke="#6366f1"
            tickFormatter={(value) => value}
            fill={isDarkMode ? '#1e293b' : '#f8fafc'}
            startIndex={startIndex}
            endIndex={endIndex}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { MessageSquareText, ArrowUpDown } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';
import { parseDateString } from '../services/dataProcessor';

interface TemporalHeatmapProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
  availableMonths: string[];
  onSendMessage: (record: FinancialRecord, context?: 'RANKING' | 'HEATMAP') => void;
}

export const TemporalHeatmap: React.FC<TemporalHeatmapProps> = ({ 
  data, 
  isDarkMode, 
  availableMonths, 
  onSendMessage
}) => {
  const [internalGroupFilter, setInternalGroupFilter] = useState<string>('ALL');

  // Filter Data
  const filteredData = useMemo(() => data.filter(item => 
    internalGroupFilter === 'ALL' || item.group === internalGroupFilter
  ), [data, internalGroupFilter]);

  // --- GLOBAL MAX FOR SMOOTH GRADIENT ---
  // Find the absolute largest difference across ALL displayed cells to normalize the gradient
  const globalMax = useMemo(() => {
    if (filteredData.length === 0) return 1;
    return Math.max(...filteredData.map(d => d.difference));
  }, [filteredData]);

  // --- CONTINUOUS HSL GRADIENT CALCULATOR ---
  const getCellStyles = (value: number, max: number, isDark: boolean) => {
    if (value === 0) {
      return {
        style: isDark 
          ? { backgroundColor: 'rgba(30, 41, 59, 0.4)', borderColor: 'rgba(30, 41, 59, 0.5)' } 
          : { backgroundColor: '#f8fafc', borderColor: '#e2e8f0' },
        className: isDark ? 'text-slate-600' : 'text-slate-300'
      };
    }

    // 1. Calculate Ratio (0 to 1)
    const ratio = max > 0 ? value / max : 0;

    // 2. Apply Sensitivity Curve (Square Root)
    // This makes smaller values more visible (visual boost)
    const adjustedRatio = Math.pow(ratio, 0.5);

    // 3. Calculate Hue (120 = Green, 60 = Yellow, 0 = Red)
    // We map 0 -> 120 and 1 -> 0
    const hue = Math.max(0, (1 - adjustedRatio) * 120);

    // 4. Calculate Lightness based on Theme
    let lightness: number;
    let borderColor: string;

    if (isDark) {
       // Dark Mode: Keep lightness low (20% - 30%) so it looks "Neon" on dark bg
       // As value increases (redder), slightly increase lightness for glow
       lightness = 20 + (adjustedRatio * 10); 
       borderColor = `hsl(${hue}, 90%, ${lightness + 10}%)`;
    } else {
       // Light Mode: Keep lightness high (95% - 85%) for pastel look
       // Border is darker
       lightness = 95 - (adjustedRatio * 15);
       borderColor = `hsl(${hue}, 70%, ${lightness - 30}%)`;
    }

    return {
      style: {
        backgroundColor: `hsl(${hue}, 85%, ${lightness}%)`,
        borderColor: borderColor,
        color: isDark ? '#fff' : '#1e293b' // High contrast text
      },
      className: 'font-bold shadow-sm'
    };
  };

  // Compact Number Formatter (399.3M, 931k)
  const formatCompact = (val: number) => {
    if (val === 0) return '-';
    if (val >= 1000000) return `${(val / 1000000).toFixed(1)}M`;
    if (val >= 1000) return `${(val / 1000).toFixed(0)}k`;
    return val.toFixed(0);
  };

  // Group Badge Color Helper (Updated to Red/Blue/Green as requested)
  const getGroupBadgeClass = (group: string) => {
    if (group === AccountGroup.BMP) 
      return 'bg-red-50 dark:bg-red-500/20 text-red-600 dark:text-red-400 border-red-200 dark:border-red-500/30 border shadow-sm dark:shadow-[0_0_5px_rgba(239,68,68,0.2)]';
    if (group === AccountGroup.CONSUMO) 
      return 'bg-blue-50 dark:bg-blue-500/20 text-blue-600 dark:text-blue-400 border-blue-200 dark:border-blue-500/30 border shadow-sm dark:shadow-[0_0_5px_rgba(59,130,246,0.2)]';
    if (group === AccountGroup.INTANGIVEL) 
      return 'bg-emerald-50 dark:bg-emerald-500/20 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-500/30 border shadow-sm dark:shadow-[0_0_5px_rgba(16,185,129,0.2)]';

    return 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-slate-300';
  };

  // Sort logic: Total Difference across all visible months
  const sortedUGs = useMemo(() => {
    const ugs = Array.from(new Set(filteredData.map(d => d.ug))) as string[];
    return ugs.sort((a, b) => {
      const sumA = filteredData.filter(r => r.ug === a).reduce((acc, r) => acc + r.difference, 0);
      const sumB = filteredData.filter(r => r.ug === b).reduce((acc, r) => acc + r.difference, 0);
      return sumB - sumA;
    });
  }, [filteredData]);

  return (
    <div className="w-full h-full flex flex-col overflow-hidden text-xs bg-white dark:bg-[#0f172a] rounded-lg border border-slate-200 dark:border-slate-700">

      {/* Header Controls */}
      <div className="flex items-center justify-between gap-2 p-3 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800">
        <div className="flex items-center gap-2 overflow-x-auto">
           {[
               { id: 'ALL', label: 'TODOS', activeClass: 'text-slate-100 bg-slate-700 dark:bg-slate-600' },
               { id: AccountGroup.BMP, label: 'BMP', activeClass: 'text-white bg-red-500 border-red-500' },
               { id: AccountGroup.CONSUMO, label: 'CONSUMO', activeClass: 'text-white bg-blue-500 border-blue-500' },
               { id: AccountGroup.INTANGIVEL, label: 'INTANGIVEL', activeClass: 'text-white bg-emerald-500 border-emerald-500' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setInternalGroupFilter(tab.id)}
                className={`px-4 py-1.5 rounded text-xs font-bold uppercase transition-all whitespace-nowrap border border-transparent
                  ${internalGroupFilter === tab.id 
                    ? tab.activeClass 
                    : 'bg-white dark:bg-slate-900 text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700 border-slate-300 dark:border-slate-600'
                  }
                `}
              >
                {tab.label}
              </button>
            ))}
        </div>

        <div className="hidden sm:flex items-center gap-1 px-3 py-1.5 rounded bg-white dark:bg-slate-900 border border-slate-300 dark:border-slate-700 text-slate-500 dark:text-slate-400 text-xs font-bold uppercase">
           <ArrowUpDown className="w-3 h-3" />
           Maior Valor
        </div>
      </div>

      {sortedUGs.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center text-slate-500 gap-2">
            <span className="text-lg">Sem dados para exibir</span>
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto custom-scrollbar bg-white dark:bg-[#0f172a] relative">
          <div className="w-full min-w-[900px] p-3">

            {/* 
               GRID LAYOUT DEFINITION - EXPANDED
               Col 1: 180px fixed (Name)
               Col 2: Auto-fit (Months) - minmax(100px, 1fr) for wider columns
               Col 3: 50px fixed (Action)
            */}
            <div 
              className="grid gap-1 mb-2 sticky top-0 z-30 pb-2 border-b border-slate-200 dark:border-slate-800 items-end bg-white dark:bg-[#0f172a]"
              style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(100px, 1fr)) 50px` }}
            >
                {/* Fixed Header Column */}
                <div className="sticky left-0 z-40 bg-white dark:bg-[#0f172a] text-slate-500 dark:text-slate-400 font-bold uppercase tracking-wider pl-2 text-xs border-r border-transparent dark:border-transparent">
                  UG / GRUPO
                </div>

                {availableMonths.map(month => (
                    <div key={month} className="text-center text-slate-500 dark:text-slate-400 font-bold uppercase text-xs truncate px-1">
                        {month.split('/')[0].substring(0, 3)}/{month.split('/')[1].substring(2,4)}
                    </div>
                ))}

                <div className="text-center text-slate-500 dark:text-slate-400 font-bold text-xs">MSG</div>
            </div>

            {/* Rows - EXPANDED HEIGHT (h-12) */}
            <div className="space-y-1.5">
              {sortedUGs.map(ug => {
                const ugRecords = filteredData.filter(d => d.ug === ug);
                const uniqueGroups = (Array.from(new Set(ugRecords.map(r => r.group))) as AccountGroup[]).sort();

                return uniqueGroups.map(group => {

                   return (
                    <div 
                        key={`${ug}-${group}`} 
                        className="grid gap-1 items-center hover:bg-slate-50 dark:hover:bg-slate-800/30 rounded transition-colors group"
                        style={{ gridTemplateColumns: `180px repeat(${availableMonths.length}, minmax(100px, 1fr)) 50px` }}
                    >

                        {/* Name Column - STICKY FIXED LEFT */}
                        <div className="sticky left-0 z-20 flex items-center h-12 overflow-hidden rounded bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700/50 pr-2 shadow-[2px_0_5px_rgba(0,0,0,0.05)] dark:shadow-[2px_0_5px_rgba(0,0,0,0.2)]">
                            <div className={`w-10 h-full flex items-center justify-center text-[9px] font-black uppercase flex-shrink-0 ${getGroupBadgeClass(group)}`}>
                                {group === AccountGroup.BMP ? 'BMP' : group === AccountGroup.CONSUMO ? 'CN' : 'INT'}
                            </div>
                            <div className="flex-1 px-3 text-slate-700 dark:text-slate-200 font-bold truncate text-sm">
                                {ug}
                            </div>
                        </div>

                        {/* Months Data Cells - CONTINUOUS GRADIENT */}
                        {availableMonths.map(month => {
                            const record = ugRecords.find(r => r.date === month && r.group === group);
                            const diff = record ? record.difference : 0;
                            const { style, className } = getCellStyles(diff, globalMax, isDarkMode);

                            return (
                                <div 
                                    key={month}
                                    style={style} // Apply dynamic HSL gradient
                                    className={`h-12 rounded flex items-center justify-center text-[11px] tracking-wide transition-all cursor-help border ${className}`}
                                    title={record ? `${month}: R$ ${diff.toLocaleString('pt-BR')}` : 'Sem dados'}
                                >
                                    {formatCompact(diff)}
                                </div>
                            );
                        })}

                        {/* Action Column */}
                        <div className="flex justify-center h-12 items-center">
                             <button 
                                onClick={() => {
                                    const latest = ugRecords.filter(r => r.group === group).sort((a, b) => parseDateString(b.date).timestamp - parseDateString(a.date).timestamp)[0];
                                    if(latest) onSendMessage(latest, 'HEATMAP');
                                }}
                                className="w-9 h-9 flex items-center justify-center rounded bg-white dark:bg-slate-800 text-slate-400 hover:text-white hover:bg-blue-600 transition-colors border border-slate-200 dark:border-slate-700 shadow-sm"
                             >
                                 <MessageSquareText className="w-4 h-4" />
                             </button>
                        </div>
                    </div>
                   );
                });
              })}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { normalizeData, formatCurrency, parseDateString, recalculateDeltas } from './services/dataProcessor';
import { parseExcelFile } from './services/excelParser';
import { AccountGroup, TimeFilter, FinancialRecord } from './types';
import { StatCard } from './components/StatCard';
import { ComparisonChart, EvolutionChart } from './components/Charts';
import { RankingList } from './components/RankingList';
import { TemporalHeatmap } from './components/TemporalHeatmap';
import { ChartWrapper } from './components/ChartWrapper';
import { FileUploadModal } from './components/FileUploadModal';
import { SiafiMessageModal } from './components/SiafiMessageModal';
import { CustomSelect } from './components/CustomSelect'; // Custom Component
import { 
  Activity, AlertTriangle, FileSpreadsheet, TrendingUp, Search, 
  LayoutDashboard, Layers, UploadCloud, Sun, Moon, Database
} from 'lucide-react';

function App() {
  // START EMPTY (No Mock Data)
  const [rawData, setRawData] = useState<any[]>([]);

  // UI State
  const [selectedGroup, setSelectedGroup] = useState<string>('ALL');
  const [timeFilter, setTimeFilter] = useState<TimeFilter>('MENSAL');
  const [selectedMonth, setSelectedMonth] = useState<string>('');
  const [selectedUG, setSelectedUG] = useState<string>('TODOS'); // New Global Filter
  const [searchTerm, setSearchTerm] = useState('');
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [hideZeros, setHideZeros] = useState(true);

  // Modals
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [isMessageModalOpen, setIsMessageModalOpen] = useState(false);
  const [selectedRecordForMessage, setSelectedRecordForMessage] = useState<FinancialRecord | null>(null);
  const [selectedHistoryForMessage, setSelectedHistoryForMessage] = useState<FinancialRecord[]>([]);
  const [messageContext, setMessageContext] = useState<'RANKING' | 'HEATMAP'>('HEATMAP');

  // Effect: Enforce Dark Mode on Body
  useEffect(() => {
    if (isDarkMode) document.documentElement.classList.add('dark');
    else document.documentElement.classList.remove('dark');
  }, [isDarkMode]);

  // 1. PROCESS DATA: Normalize -> Recalculate Deltas
  const allData = useMemo(() => {
    const normalized = normalizeData(rawData);
    // Recalculate deltas based on whether we are looking Month-over-Month or Year-over-Year, etc.
    return recalculateDeltas(normalized, timeFilter);
  }, [rawData, timeFilter]);

  // 2. EXTRACT DROPDOWN LISTS
  const uniqueMonths = useMemo(() => {
    const dates = Array.from(new Set(allData.map(d => d.date))) as string[];
    return dates.sort((a, b) => parseDateString(a).timestamp - parseDateString(b).timestamp);
  }, [allData]);

  const uniqueUGs = useMemo(() => Array.from(new Set(allData.map(d => d.ug))).sort(), [allData]);

  // Auto-select latest month when data loads
  useEffect(() => {
    if (uniqueMonths.length > 0 && !selectedMonth) {
      setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    } else if (uniqueMonths.length > 0 && !uniqueMonths.includes(selectedMonth)) {
        // If current selection is invalid after new upload
        setSelectedMonth(uniqueMonths[uniqueMonths.length - 1]);
    }
  }, [uniqueMonths, selectedMonth]);

  // 3. FILTERING LOGIC SPLIT

  // 3a. Base Filter (Applied to everything: Search + Global UG Selection)
  // We do NOT apply hideZeros here, because we want Totals to reflect the true Accounting Balance
  const baseFilteredData = useMemo(() => {
    return allData.filter(item => {
      const matchSearch = item.ug.toLowerCase().includes(searchTerm.toLowerCase()) || item.cod.includes(searchTerm);
      const matchUG = selectedUG === 'TODOS' || item.ug === selectedUG;
      return matchSearch && matchUG;
    });
  }, [allData, searchTerm, selectedUG]);

  // 3b. Visualization Filter (Applied to Lists, Charts, Heatmaps)
  // This DOES apply hideZeros to reduce clutter
  const filteredDataForVisuals = useMemo(() => {
    return baseFilteredData.filter(item => {
      const matchZero = hideZeros ? item.difference !== 0 : true;
      return matchZero;
    });
  }, [baseFilteredData, hideZeros]);

  // 3c. KPI Data (Current Month Only, Respects Group)
  // We derive this from baseFilteredData (INCLUDES ZEROS) so totals are correct
  const kpiData = useMemo(() => {
    return baseFilteredData.filter(item => 
        item.date === selectedMonth && 
        (selectedGroup === 'ALL' || item.group === selectedGroup)
    );
  }, [baseFilteredData, selectedMonth, selectedGroup]);

  // Subset: Current Month Visuals (for Comparison Chart & Counter) - Derived from Visuals (Excludes Zeros if toggled)
  const currentMonthVisuals = useMemo(() => {
    return filteredDataForVisuals.filter(item => 
        item.date === selectedMonth && 
        (selectedGroup === 'ALL' || item.group === selectedGroup)
    );
  }, [filteredDataForVisuals, selectedMonth, selectedGroup]);


  // 4. KPI CALCULATIONS
  const stats = useMemo(() => {
    // FINANCIAL TOTALS: Use kpiData (includes zeros) to match official accounting balance (Spreadsheet)
    const totalDiff = kpiData.reduce((acc, curr) => acc + curr.difference, 0);
    const totalSiafi = kpiData.reduce((acc, curr) => acc + curr.siafiValue, 0);
    const totalSiloms = kpiData.reduce((acc, curr) => acc + curr.silomsValue, 0);

    // VISUAL COUNTS: Use currentMonthVisuals (respects hideZeros) so the user sees count of what's on screen
    const topOffender = currentMonthVisuals.length > 0 
        ? currentMonthVisuals.reduce((prev, current) => (prev.difference > current.difference) ? prev : current)
        : null;

    // Count Unique UGs in the current VISUAL scope (changes with filters)
    const totalUGsCount = new Set(currentMonthVisuals.map(d => d.ug)).size;

    return { totalDiff, totalSiafi, totalSiloms, topOffender, totalUGsCount };
  }, [kpiData, currentMonthVisuals]);

  // Determine Comparison Label for Ranking
  const comparisonLabel = useMemo(() => {
     if (!selectedMonth || kpiData.length === 0) return `Comparando ${timeFilter}`;
     const sampleRecord = kpiData[0];

     // Current Date Short Format (SET/25)
     const currShortYear = sampleRecord.year.toString().slice(-2);
     const currMonthNames = ['JAN', 'FEV', 'MAR', 'ABR', 'MAI', 'JUN', 'JUL', 'AGO', 'SET', 'OUT', 'NOV', 'DEZ'];
     const currShort = `${currMonthNames[sampleRecord.monthIndex]}/${currShortYear}`;

     // Previous Date (Already formatted in recalculateDeltas as MON/YY)
     const prevDate = sampleRecord.previousDate || 'N/A';

     return `Comparando ${currShort} contra ${prevDate}`;
  }, [kpiData, selectedMonth, timeFilter]);

  // Handlers
  const handleFileUpload = async (file: File) => {
    try {
      const parsed = await parseExcelFile(file);
      if (parsed.length > 0) {
        setRawData(parsed);
        alert(`Sucesso! ${parsed.length} linhas processadas.`);
      } else {
        alert("Arquivo vazio ou formato não reconhecido.");
      }
    } catch (e) {
      console.error(e);
      alert("Erro crítico ao processar arquivo. Verifique se é um Excel válido.");
    }
  };

  const handleOpenMessage = (record: FinancialRecord, context: 'RANKING' | 'HEATMAP' = 'HEATMAP') => {
    // 1. Find full history for this specific UG and Group
    const history = allData.filter(item => 
      item.ug === record.ug && 
      item.group === record.group &&
      item.cod === record.cod // Ensure precise match
    );

    setSelectedHistoryForMessage(history);
    setSelectedRecordForMessage(record);
    setMessageContext(context); // Set context for modal
    setIsMessageModalOpen(true);
  };

  return (
    <div className={`min-h-screen pb-12 transition-colors duration-300 ${isDarkMode ? 'bg-[#020617] text-slate-100' : 'bg-slate-50 text-slate-900'}`}>

      <FileUploadModal 
        isOpen={isUploadModalOpen} 
        onClose={() => setIsUploadModalOpen(false)} 
        onUpload={handleFileUpload} 
      />

      <SiafiMessageModal 
        isOpen={isMessageModalOpen}
        onClose={() => setIsMessageModalOpen(false)}
        record={selectedRecordForMessage}
        history={selectedHistoryForMessage}
        context={messageContext}
      />

      {/* STICKY TOP BAR - MAIN NAVIGATION */}
      <nav className={`${isDarkMode ? 'bg-[#0f172a]/95 border-slate-800' : 'bg-white/95 border-slate-200'} border-b sticky top-0 z-40 backdrop-blur-md`}>
        <div className="max-w-[1800px] mx-auto px-4 sm:px-6 h-16 flex items-center justify-between gap-4">

          <div className="flex items-center gap-3 min-w-max">
             <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-500/20">
               <Activity className="w-5 h-5 text-white" />
             </div>
             <h1 className={`text-lg font-bold tracking-tight hidden lg:block ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
               SIAFI <span className="text-slate-500 mx-1">x</span> SILOMS
             </h1>
          </div>

          <div className="flex-1 flex items-center justify-end gap-3 max-w-3xl">
            {/* Custom Select for UG (Global Filter) */}
            <div className="w-48 hidden md:block">
                <CustomSelect 
                    value={selectedUG} 
                    onChange={setSelectedUG} 
                    options={[{ value: 'TODOS', label: 'Todas as UGs' }, ...uniqueUGs.map(ug => ({ value: ug, label: ug }))]}
                    placeholder="Filtrar UG"
                />
            </div>

            {/* Custom Select for Month */}
            <div className="w-40 hidden md:block">
                <CustomSelect 
                    value={selectedMonth} 
                    onChange={setSelectedMonth} 
                    options={uniqueMonths.map(m => ({ value: m, label: m }))}
                    placeholder="Mês de Ref."
                />
            </div>

            <button 
              onClick={() => setIsUploadModalOpen(true)}
              className="flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-bold bg-blue-600 hover:bg-blue-500 text-white transition-all shadow-lg shadow-blue-900/20 whitespace-nowrap"
            >
              <UploadCloud className="w-4 h-4" />
              <span className="hidden sm:inline">Importar Excel</span>
            </button>

             <button 
              onClick={() => setIsDarkMode(!isDarkMode)}
              className={`p-2 rounded-full transition-colors border ${isDarkMode ? 'hover:bg-slate-800 text-slate-400 border-transparent' : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-100'}`}
            >
              {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-[1800px] mx-auto px-4 sm:px-6 space-y-6">

        {/* EMPTY STATE */}
        {allData.length === 0 && (
          <div className={`flex flex-col items-center justify-center py-20 border-2 border-dashed rounded-xl mt-8
             ${isDarkMode ? 'border-slate-800 bg-slate-900/50' : 'border-slate-300 bg-white'}
          `}>
            <FileSpreadsheet className={`w-16 h-16 mb-4 ${isDarkMode ? 'text-slate-600' : 'text-slate-400'}`} />
            <h2 className={`text-xl font-bold ${isDarkMode ? 'text-slate-300' : 'text-slate-700'}`}>Nenhum dado carregado</h2>
            <p className="text-slate-500 mb-6">Importe uma planilha para começar a auditoria.</p>
            <button 
              onClick={() => setIsUploadModalOpen(true)}
              className="px-6 py-3 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-500 transition-colors"
            >
              Carregar Arquivo .XLSX
            </button>
          </div>
        )}

        {allData.length > 0 && (
          <>
            {/* CONTROLS BAR - STICKY BELOW NAVBAR */}
            <div className={`sticky top-16 z-30 pt-4 pb-2 transition-colors ${isDarkMode ? 'bg-[#020617]/95' : 'bg-slate-50/95'} backdrop-blur-md -mx-4 px-4 sm:-mx-6 sm:px-6`}>
              <div className={`grid grid-cols-1 md:grid-cols-12 gap-4 items-center p-2 rounded-xl border shadow-sm
                ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-white border-slate-200'}
              `}>
                 {/* Group Filters */}
                 <div className="col-span-1 md:col-span-5 flex items-center gap-2 p-1 bg-transparent rounded-lg overflow-x-auto">
                   {[
                     { id: 'ALL', label: 'VISÃO GERAL', activeClass: 'bg-slate-700 text-white' },
                     { id: AccountGroup.BMP, label: 'BMP', activeClass: 'text-red-500 border border-red-500 shadow-[0_0_10px_rgba(239,68,68,0.2)]' },
                     { id: AccountGroup.CONSUMO, label: 'CONSUMO', activeClass: 'text-blue-500 border border-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.2)]' },
                     { id: AccountGroup.INTANGIVEL, label: 'INTANGÍVEL', activeClass: 'text-emerald-500 border border-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.2)]' }
                   ].map(tab => (
                      <button
                        key={tab.id}
                        onClick={() => setSelectedGroup(tab.id)}
                        className={`px-4 py-2 text-xs font-bold rounded-lg transition-all whitespace-nowrap border border-transparent
                          ${selectedGroup === tab.id 
                             ? `${tab.activeClass}` 
                             : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-800/50'
                          }
                        `}
                      >
                        {tab.label}
                      </button>
                   ))}
                 </div>

                 {/* Time Filters */}
                 <div className="col-span-1 md:col-span-4 flex justify-center">
                    <div className={`flex p-1 rounded-lg ${isDarkMode ? 'bg-slate-900' : 'bg-slate-100'}`}>
                      {['MENSAL', 'TRIMESTRAL', 'SEMESTRAL', 'ANUAL'].map((tf) => (
                          <button
                            key={tf}
                            onClick={() => setTimeFilter(tf as TimeFilter)}
                            className={`px-3 py-2 text-xs font-bold rounded-md transition-all
                              ${timeFilter === tf 
                                ? 'bg-indigo-600 text-white shadow-sm' 
                                : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
                              }
                            `}
                          >
                            {tf}
                          </button>
                      ))}
                    </div>
                 </div>

                 {/* Toggles & Stats */}
                 <div className="col-span-1 md:col-span-3 flex justify-end items-center gap-3">

                     {/* Added: Total Records Counter */}
                     <div className={`flex items-center gap-2 px-3 py-2 rounded-lg border 
                       ${isDarkMode ? 'bg-slate-900/50 border-slate-700/50' : 'bg-slate-100 border-slate-200'}`} 
                       title="Quantidade de UGs consideradas na visualização atual"
                     >
                        <Database className="w-3.5 h-3.5 text-blue-500" />
                        <div className="flex flex-col leading-none">
                            <span className="text-[9px] text-slate-500 font-bold uppercase">Registros Totais</span>
                            <span className={`text-xs font-bold ${isDarkMode ? 'text-slate-200' : 'text-slate-800'}`}>{stats.totalUGsCount} UGs</span>
                        </div>
                     </div>

                     <button 
                      onClick={() => setHideZeros(!hideZeros)}
                      className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold border transition-all
                        ${hideZeros 
                          ? 'bg-amber-500/10 text-amber-500 border-amber-500/50' 
                          : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700'
                        }
                      `}
                     >
                       <AlertTriangle className="w-4 h-4" />
                       {hideZeros ? 'Ocultando Zerados' : 'Mostrar Zerados'}
                     </button>
                 </div>
              </div>
            </div>

            {/* KPIS */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 pt-2">
              <StatCard 
                title="Diferença Total" value={formatCurrency(stats.totalDiff)} 
                subtitle={selectedMonth} icon={TrendingUp} colorClass="text-red-500" bgClass="bg-red-500" 
              />
              <StatCard 
                title="Saldo SIAFI" value={formatCurrency(stats.totalSiafi)} 
                subtitle="Contábil (Completo)" icon={LayoutDashboard} colorClass="text-blue-500" bgClass="bg-blue-500" 
              />
              <StatCard 
                title="Saldo SILOMS" value={formatCurrency(stats.totalSiloms)} 
                subtitle="Físico (Completo)" icon={Layers} colorClass="text-emerald-500" bgClass="bg-emerald-500" 
              />
              <StatCard 
                title="Maior Divergência" value={stats.topOffender?.ug || '-'} 
                subtitle={stats.topOffender ? formatCurrency(stats.topOffender.difference) : '-'} 
                icon={AlertTriangle} colorClass="text-amber-500" bgClass="bg-amber-500" 
              />
            </div>

            {/* TOP ROW: RANKING */}
            <ChartWrapper
              title={`Ranking de Evolução (${timeFilter === 'ANUAL' ? 'ANO' : timeFilter.substring(0,3)})`}
              className="h-[500px]"
              allData={filteredDataForVisuals} // Passing visual data (may hide zeros)
              availableMonths={uniqueMonths}
              availableUGs={uniqueUGs}
              isDarkMode={isDarkMode}
              defaultMonth={selectedMonth}
              defaultGroup={selectedGroup}
            >
              {(data) => <RankingList 
                data={data} 
                isDarkMode={isDarkMode} 
                comparisonLabel={comparisonLabel}
                onSendMessage={handleOpenMessage} 
              />}
            </ChartWrapper>

