  { key: 'DIRETORIAS', label: 'DIRETORIAS', color: '#60a5fa', match: (ug: string) => ug.startsWith('DIR') },
  { key: 'OUTROS', label: 'OUTROS', color: '#93c5fd', match: () => true } // Fallback
];

// Custom Content for Treemap Tiles
const CustomContent = (props: any) => {
  const { root, depth, x, y, width, height, index, name, value, categoryColor } = props;

  return (
    <g>
      <rect
        x={x}
        y={y}
        width={width}
        height={height}
        style={{
          fill: categoryColor, // Use the color passed from data
          stroke: '#fff',
          strokeWidth: 2 / (depth + 1e-10),
          strokeOpacity: 1 / (depth + 1e-10),
        }}
