export const TreemapChart: React.FC<TreemapChartProps> = ({ data, isDarkMode }) => {
  if (!data || data.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  interface AggregatedNode {
    name: string;
    size: number;
    group: string;
  }

  // 1. Aggregate Data by UG (Sum differences across groups/months if needed, but usually Treemap is a snapshot)
  // We assume 'data' passed here is already filtered to the relevant view (e.g., current month)
  const aggregatedByUG = data.reduce((acc, curr) => {
    if (!acc[curr.ug]) {
      acc[curr.ug] = { name: curr.ug, size: 0, group: '' };
    }
    acc[curr.ug].size += curr.difference;
    return acc;
  }, {} as Record<string, AggregatedNode>);

  // 2. Assign Categories
  const categorizedNodes: Record<string, any[]> = {};

  Object.values(aggregatedByUG).forEach((item: AggregatedNode) => {
    // Skip tiny values to reduce clutter
    if (item.size < 100) return;

    const cat = CATEGORIES.find(c => c.match(item.name)) || CATEGORIES[CATEGORIES.length - 1];
    if (!categorizedNodes[cat.label]) {
      categorizedNodes[cat.label] = [];
    }
    // Inject the category color into the item for the custom renderer
    categorizedNodes[cat.label].push({ ...item, categoryColor: cat.color });
  });

  // 3. Build Tree Structure
  const treeData = Object.keys(categorizedNodes).map(catName => ({
    name: catName,
    children: categorizedNodes[catName]
  }));

  return (
    <div className="w-full h-full">
      <ResponsiveContainer width="100%" height="100%">
        <Treemap
          data={treeData}
          dataKey="size"
          ratio={4 / 3}
          stroke="#fff"
          fill="#8884d8"
          content={<CustomContent />}
        >
           <Tooltip 
             content={({ active, payload }) => {
                if (active && payload && payload.length) {
                   const d = payload[0].payload;
                   return (
                     <div className={`p-3 rounded shadow-lg border backdrop-blur-md ${isDarkMode ? 'bg-slate-900/90 border-slate-700' : 'bg-white/90 border-slate-200'}`}>
                        <p className={`font-bold ${isDarkMode ? 'text-white' : 'text-slate-800'}`}>{d.name}</p>
                        <p className="text-sm font-mono text-blue-500">{formatCurrency(d.value)}</p>
                     </div>
                   )
                }
                return null;
             }}
           />
        </Treemap>
      </ResponsiveContainer>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { ResponsiveContainer, Treemap, Tooltip } from 'recharts';
import { FinancialRecord } from '../types';
