interface TreemapChartProps {
  data: FinancialRecord[];
  isDarkMode: boolean;
}

// Updated Palette: Navy, Teal, Deep Blue, Indigo (Professional/Dark Aesthetic)
const CATEGORIES = [
  { key: 'GAP', label: 'GAPS', color: '#0e7490', match: (ug: string) => ug.startsWith('GAP') }, // Cyan-700 (Teal-ish)
  { key: 'BASES', label: 'BASES', color: '#0f172a', match: (ug: string) => ug.startsWith('BA') || ug.startsWith('ALA') }, // Slate-900 (Deep Navy)
  { key: 'PAMA', label: 'PARQUES', color: '#1d4ed8', match: (ug: string) => ug.startsWith('PAMA') }, // Blue-700 (Strong Blue)
  { key: 'SAUDE', label: 'SAÚDE', color: '#4338ca', match: (ug: string) => ['HCA', 'HFASP', 'HFAG', 'HFAB', 'HOSP', 'ODONTO'].some(k => ug.includes(k)) }, // Indigo-700
  { key: 'DECEA', label: 'DECEA', color: '#1e3a8a', match: (ug: string) => ug.includes('CINDACTA') || ug.includes('DTCEA') || ug.includes('CISCEA') }, // Blue-900
  { key: 'DIRETORIAS', label: 'DIRETORIAS', color: '#0369a1', match: (ug: string) => ug.startsWith('DIR') }, // Sky-700
  { key: 'OUTROS', label: 'OUTROS', color: '#334155', match: () => true } // Slate-700 (Grey)
];

// Helper to find category
const getCategory = (ugName: string) => {
  return CATEGORIES.find(c => c.match(ugName)) || CATEGORIES[CATEGORIES.length - 1];
};

// Custom Content for Treemap Tiles
const CustomContent = (props: any) => {
  const { x, y, width, height, name, value, itemColor } = props;

  // Don't render if too small
  if (width < 5 || height < 5) return null;

  return (
    <g>
      <rect
        x={x}
        y={y}
        width={width}
        height={height}
        style={{
          fill: itemColor || '#8884d8',
          stroke: '#fff',
          strokeWidth: 1,
          strokeOpacity: 0.2,
        }}
      />
      {width > 40 && height > 25 && (
        <text
          x={x + width / 2}
          y={y + height / 2}
          textAnchor="middle"
          fill="#fff"
          fontSize={Math.min(width / 6, 11)}
          fontWeight="800"
          dy={-6}
          style={{ textShadow: '0px 1px 2px rgba(0,0,0,0.5)' }}
        >
          {name}
        </text>
      )}
      {width > 60 && height > 40 && (
        <text
          x={x + width / 2}
          y={y + height / 2}
          textAnchor="middle"
          fill="rgba(255,255,255,0.9)"
          fontSize={Math.min(width / 7, 10)}
          dy={8}
          style={{ textShadow: '0px 1px 2px rgba(0,0,0,0.5)' }}
        >
          {formatCurrency(value).split(',')[0]}
        </text>
      )}
    </g>
  );
};

export const TreemapChart: React.FC<TreemapChartProps> = ({ data, isDarkMode }) => {
  // State for Filters
  const [activeCategories, setActiveCategories] = useState<string[]>(CATEGORIES.map(c => c.key));

  const toggleCategory = (key: string) => {
    setActiveCategories(prev => 
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  if (!data || data.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  interface AggregatedNode {
    name: string;
    size: number;
    categoryKey: string;
    categoryColor: string;
    categoryLabel: string;
  }

  // 1. Aggregate Data by UG (Flat List)
  const aggregatedData = useMemo(() => {
    const map = data.reduce((acc, curr) => {
      if (!acc[curr.ug]) {
        const cat = getCategory(curr.ug);
        acc[curr.ug] = { 
            name: curr.ug, 
            size: 0, 
            categoryKey: cat.key,
            categoryColor: cat.color,
            categoryLabel: cat.label
        };
      }
      acc[curr.ug].size += curr.difference;
      return acc;
    }, {} as Record<string, AggregatedNode>);

    // Convert to array and filter by active categories
    return Object.values(map)
      .filter(item => activeCategories.includes(item.categoryKey))
      .filter(item => item.size > 0) // Hide zeros if any passed through
      .sort((a, b) => b.size - a.size); // Sort by size descending
  }, [data, activeCategories]);

  // 2. Format for Recharts (Flat Root)
  const treeData = [
    {
      name: 'root',
      children: aggregatedData.map(item => ({
        ...item,
        // Recharts Treemap looks for 'value' or 'size'. We'll map 'size' in prop.
        // We inject color into the node so CustomContent can read it
        itemColor: item.categoryColor 
      }))
    }
  ];

  return (
    <div className="flex flex-col h-full w-full">

      {/* Category Filters Bar */}
      <div className="flex flex-wrap items-center gap-2 mb-3 pb-2 border-b border-slate-200 dark:border-slate-800">
        <div className="flex items-center gap-2 mr-2 text-xs font-bold text-slate-400">
            <Filter className="w-3 h-3" />
            <span>FILTROS:</span>
        </div>
        {CATEGORIES.map(cat => {
            const isActive = activeCategories.includes(cat.key);
            return (
                <button
                    key={cat.key}
                    onClick={() => toggleCategory(cat.key)}
                    className={`flex items-center gap-1.5 px-2.5 py-1 rounded text-[10px] font-bold uppercase transition-all border
                        ${isActive 
                            ? 'text-white border-transparent shadow-sm' 
                            : 'bg-transparent text-slate-400 border-slate-300 dark:border-slate-700 hover:border-slate-500'
                        }
                    `}
                    style={{ backgroundColor: isActive ? cat.color : 'transparent' }}
                >
                    {cat.label}
                    {!isActive && <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: cat.color }}></div>}
                    {isActive && <XCircle className="w-3 h-3 text-white/70" />}
                </button>
            )
        })}
        {aggregatedData.length === 0 && (
            <span className="text-xs text-red-500 ml-auto">Nenhum dado selecionado.</span>
        )}
      </div>

      {/* Chart Area */}
      <div className="flex-1 min-h-0">
        <ResponsiveContainer width="100%" height="100%">
            <Treemap
                data={treeData}
                dataKey="size"
                aspectRatio={4 / 3}
                stroke="#fff"
                content={<CustomContent />}
                isAnimationActive={false} // Performance
            >
                <Tooltip 
                    cursor={{ stroke: 'rgba(255,255,255,0.5)', strokeWidth: 2 }}
                    content={({ active, payload }) => {
                        if (active && payload && payload.length) {
                        const d = payload[0].payload;
                        return (
                            <div className={`p-3 rounded-lg shadow-xl border backdrop-blur-md z-50 
                                ${isDarkMode ? 'bg-slate-900/95 border-slate-700' : 'bg-white/95 border-slate-200'}`}>
                                <div className="flex items-center gap-2 mb-1">
                                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: d.itemColor }}></div>
                                    <span className={`text-[10px] font-bold uppercase ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>
                                        {d.categoryLabel}
                                    </span>
                                </div>
                                <p className={`text-sm font-black ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{d.name}</p>
                                <p className="text-sm font-mono text-emerald-500 font-bold mt-1">{formatCurrency(d.value)}</p>
                            </div>
                        )
                        }
                        return null;
                    }}
                />
            </Treemap>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

