import React, { useState, useMemo, useEffect } from 'react';
import { Maximize2, Minimize2, X, Filter, Info } from 'lucide-react';
import { FinancialRecord, AccountGroup } from '../types';

interface ChartWrapperProps {
  title: string;
  description?: string;
  allData: FinancialRecord[];
  children: (filteredData: FinancialRecord[], isExpanded: boolean) => React.ReactNode;
  availableMonths: string[];
  availableUGs: string[];
  isDarkMode: boolean;
  defaultGroup?: string; 
  defaultMonth?: string;
  hideMonthFilter?: boolean;
  className?: string;
}

export const ChartWrapper: React.FC<ChartWrapperProps> = ({
  title,
  description,
  allData,
  children,
  availableMonths,
  availableUGs,
  isDarkMode,
  defaultGroup = 'ALL',
  defaultMonth = 'TODOS',
  hideMonthFilter = false,
  className = ''
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [localMonth, setLocalMonth] = useState<string>(defaultMonth);
  const [localUG, setLocalUG] = useState<string>('TODOS');
  const [localGroup, setLocalGroup] = useState<string>(defaultGroup);

  useEffect(() => { setLocalMonth(defaultMonth); }, [defaultMonth]);
  useEffect(() => { setLocalGroup(defaultGroup); }, [defaultGroup]);

  const filteredData = useMemo(() => {
    return allData.filter(item => {
      const matchGroup = localGroup === 'ALL' || item.group === localGroup;
      const matchMonth = localMonth === 'TODOS' || item.date === localMonth;
      const matchUG = localUG === 'TODOS' || item.ug === localUG;
      return matchGroup && matchMonth && matchUG;
    });
  }, [allData, localMonth, localUG, localGroup]);

  const Controls = () => (
    <div className="flex flex-wrap items-center gap-2 mt-2 sm:mt-0">
      <div className="relative">
