  if (isExpanded) {
    return (
      <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/70 backdrop-blur-md p-2 animate-in fade-in zoom-in-95 duration-200">
        <div className={`w-[98vw] h-[96vh] rounded-xl shadow-2xl flex flex-col overflow-hidden
