    return (
      <div className={`min-w-[220px] p-4 rounded-xl border shadow-2xl backdrop-blur-md z-50 
        ${isDarkMode ? 'bg-[#0f172a]/95 border-slate-700' : 'bg-white/95 border-slate-200'}
