  { key: 'SAUDE', label: 'SAÚDE', color: '#4338ca', match: (ug: string) => ['HCA', 'HFASP', 'HFAG', 'HFAB', 'HOSP', 'ODONTO'].some(k => ug.includes(k)) }, // Indigo-700
  { key: 'DECEA', label: 'DECEA', color: '#1e3a8a', match: (ug: string) => ug.includes('CINDACTA') || ug.includes('DTCEA') || ug.includes('CISCEA') }, // Blue-900
  { key: 'DIRETORIAS', label: 'DIRETORIAS', color: '#0369a1', match: (ug: string) => ug.startsWith('DIR') }, // Sky-700
  { key: 'OUTROS', label: 'OUTROS', color: '#334155', match: () => true } // Slate-700 (Grey)
];

// Helper to find category
const getCategory = (ugName: string) => {
  return CATEGORIES.find(c => c.match(ugName)) || CATEGORIES[CATEGORIES.length - 1];
};

// Custom Content for Treemap Tiles
const CustomContent = (props: any) => {
  const { x, y, width, height, name, value, itemColor } = props;

  // Don't render if too small
  if (width < 5 || height < 5) return null;

  return (
    <g>
      <rect
        x={x}
        y={y}
        width={width}
        height={height}
        style={{
          fill: itemColor || '#8884d8',
          stroke: '#fff',
          strokeWidth: 1,
          strokeOpacity: 0.2,
        }}
      />
      {width > 40 && height > 25 && (
        <text
          x={x + width / 2}
          y={y + height / 2}
          textAnchor="middle"
          fill="#fff"
          fontSize={Math.min(width / 6, 11)}
          fontWeight="800"
          dy={-6}
          style={{ textShadow: '0px 1px 2px rgba(0,0,0,0.5)' }}
        >
          {name}
        </text>
      )}
      {width > 60 && height > 40 && (
        <text
          x={x + width / 2}
          y={y + height / 2}
          textAnchor="middle"
          fill="rgba(255,255,255,0.9)"
          fontSize={Math.min(width / 7, 10)}
          dy={8}
          style={{ textShadow: '0px 1px 2px rgba(0,0,0,0.5)' }}
        >
          {formatCurrency(value).split(',')[0]}
        </text>
      )}
    </g>
  );
};

export const TreemapChart: React.FC<TreemapChartProps> = ({ data, isDarkMode }) => {
  // State for Filters
  const [activeCategories, setActiveCategories] = useState<string[]>(CATEGORIES.map(c => c.key));

  const toggleCategory = (key: string) => {
    setActiveCategories(prev => 
      prev.includes(key) ? prev.filter(k => k !== key) : [...prev, key]
    );
  };

  if (!data || data.length === 0) return <div className="flex items-center justify-center h-full text-slate-500">Sem dados.</div>;

  interface AggregatedNode {
    name: string;
    size: number;
    categoryKey: string;
    categoryColor: string;
    categoryLabel: string;
  }

  // 1. Aggregate Data by UG (Flat List)
  const aggregatedData = useMemo(() => {
    const map = data.reduce((acc, curr) => {
      if (!acc[curr.ug]) {
        const cat = getCategory(curr.ug);
        acc[curr.ug] = { 
            name: curr.ug, 
            size: 0, 
            categoryKey: cat.key,
            categoryColor: cat.color,
            categoryLabel: cat.label
        };
      }
      acc[curr.ug].size += curr.difference;
      return acc;
    }, {} as Record<string, AggregatedNode>);

    // Convert to array and filter by active categories
    return (Object.values(map) as AggregatedNode[])
      .filter(item => activeCategories.includes(item.categoryKey))
      .filter(item => item.size > 0) // Hide zeros if any passed through
      .sort((a, b) => b.size - a.size); // Sort by size descending
  }, [data, activeCategories]);

  // 2. Format for Recharts (Flat Root)
  const treeData = [
    {
      name: 'root',
      children: aggregatedData.map(item => ({
        ...item,
        // Recharts Treemap looks for 'value' or 'size'. We'll map 'size' in prop.
        // We inject color into the node so CustomContent can read it
        itemColor: item.categoryColor 
      }))
    }
  ];

  return (
    <div className="flex flex-col h-full w-full">

      {/* Category Filters Bar */}
      <div className="flex flex-wrap items-center gap-2 mb-3 pb-2 border-b border-slate-200 dark:border-slate-800">
        <div className="flex items-center gap-2 mr-2 text-xs font-bold text-slate-400">
            <Filter className="w-3 h-3" />
            <span>FILTROS:</span>
        </div>
        {CATEGORIES.map(cat => {
            const isActive = activeCategories.includes(cat.key);
            return (
                <button
                    key={cat.key}
                    onClick={() => toggleCategory(cat.key)}
                    className={`flex items-center gap-1.5 px-2.5 py-1 rounded text-[10px] font-bold uppercase transition-all border
                        ${isActive 
                            ? 'text-white border-transparent shadow-sm' 
                            : 'bg-transparent text-slate-400 border-slate-300 dark:border-slate-700 hover:border-slate-500'
                        }
                    `}
                    style={{ backgroundColor: isActive ? cat.color : 'transparent' }}
                >
                    {cat.label}
                    {!isActive && <div className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: cat.color }}></div>}
                    {isActive && <XCircle className="w-3 h-3 text-white/70" />}
                </button>
            )
        })}
        {aggregatedData.length === 0 && (
            <span className="text-xs text-red-500 ml-auto">Nenhum dado selecionado.</span>
        )}
      </div>

      {/* Chart Area */}
      <div className="flex-1 min-h-0">
        <ResponsiveContainer width="100%" height="100%">
            <Treemap
                data={treeData}
                dataKey="size"
                aspectRatio={4 / 3}
                stroke="#fff"
                content={<CustomContent />}
                isAnimationActive={false} // Performance
            >
                <Tooltip 
                    cursor={{ stroke: 'rgba(255,255,255,0.5)', strokeWidth: 2 }}
                    content={({ active, payload }) => {
                        if (active && payload && payload.length) {
                        const d = payload[0].payload;
                        return (
                            <div className={`p-3 rounded-lg shadow-xl border backdrop-blur-md z-50 
                                ${isDarkMode ? 'bg-slate-900/95 border-slate-700' : 'bg-white/95 border-slate-200'}`}>
                                <div className="flex items-center gap-2 mb-1">
                                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: d.itemColor }}></div>
                                    <span className={`text-[10px] font-bold uppercase ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>
                                        {d.categoryLabel}
                                    </span>
                                </div>
                                <p className={`text-sm font-black ${isDarkMode ? 'text-white' : 'text-slate-900'}`}>{d.name}</p>
                                <p className="text-sm font-mono text-emerald-500 font-bold mt-1">{formatCurrency(d.value)}</p>
                            </div>
                        )
                        }
                        return null;
                    }}
                />
            </Treemap>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import { FinancialRecord, RawInputRow, AccountGroup, TimeFilter } from '../types';

// Helper to safely parse dates in format "MONTH/YEAR", "Mon/Year", "Mon-Year"
export const parseDateString = (dateStr: string): { month: number, year: number, timestamp: number } => {
  try {
    if (!dateStr) return { month: 0, year: 0, timestamp: 0 };

    // Replace dashes with slashes to handle "NOV-25" style
    const normalizedStr = dateStr.replace(/-/g, '/');
    const parts = normalizedStr.split('/');

    if (parts.length < 2) return { month: 0, year: 0, timestamp: 0 };

    const [monthStr, yearStr] = parts;
    const months: Record<string, number> = {
      'JANEIRO': 0, 'FEVEREIRO': 1, 'MARÇO': 2, 'ABRIL': 3, 'MAIO': 4, 'JUNHO': 5,
      'JULHO': 6, 'AGOSTO': 7, 'SETEMBRO': 8, 'OUTUBRO': 9, 'NOVEMBRO': 10, 'DEZEMBRO': 11,
      'JAN': 0, 'FEV': 1, 'MAR': 2, 'ABR': 3, 'MAI': 4, 'JUN': 5,
      'JUL': 6, 'AGO': 7, 'SET': 8, 'OUT': 9, 'NOV': 10, 'DEZ': 11,
      'DEZ.': 11, 'NOV.': 10, 'OUT.': 9, 'SET.': 8, 'AGO.': 7, 'JUL.': 6, // Handle abbreviated dots
      'JUN.': 5, 'MAI.': 4, 'ABR.': 3, 'MAR.': 2, 'FEV.': 1, 'JAN.': 0
    };

    const cleanMonth = monthStr.trim().toUpperCase();
    const month = months[cleanMonth] !== undefined ? months[cleanMonth] : 0;

    let year = parseInt(yearStr) || new Date().getFullYear();

    // FIX: Handle 2-digit years (e.g., "25" -> 2025)
    if (year < 100) {
      year += 2000;
    }

    return {
      month,
      year,
      timestamp: new Date(year, month, 1).getTime()
    };
  } catch (e) {
    console.error("Date Parse Error", e);
    return { month: 0, year: 0, timestamp: 0 };
  }
};

// Helper to convert long date strings (JANEIRO/2025) to short (JAN/2025)
export const toShortDate = (dateStr: string): string => {
    const { month, year } = parseDateString(dateStr);
    const monthNames = ['JAN', 'FEV', 'MAR', 'ABR', 'MAI', 'JUN', 'JUL', 'AGO', 'SET', 'OUT', 'NOV', 'DEZ'];
    return `${monthNames[month]}/${year}`;
};

// --- DATA NORMALIZATION ---
export const normalizeData = (rawRows: RawInputRow[]): FinancialRecord[] => {
  const normalized: FinancialRecord[] = [];
  if (!rawRows || !Array.isArray(rawRows)) return [];

  rawRows.forEach((row, index) => {
    // Defensive check
    if (!row) return;

    const { month, year } = parseDateString(row.data);
    // CRITICAL FIX: Trim COD and UG to ensure historical matching works even with trailing spaces
    const safeCod = row.cod ? String(row.cod).trim() : '000000';
    const safeUg = row.ug ? String(row.ug).trim() : 'DESCONHECIDO';

    // Helper to process a group safely
    const processGroup = (groupEnum: AccountGroup, siafi: number, siloms: number, explicitDiff: number) => {
      // Logic: Use explicit diff if present (and logically valid), else calc
      const finalDiff = explicitDiff !== 0 ? Math.abs(explicitDiff) : Math.abs(siafi - siloms);

      let preponderance: 'SIAFI' | 'SILOMS' | 'EQUAL' = 'EQUAL';
      if (siafi > siloms) preponderance = 'SIAFI';
      if (siloms > siafi) preponderance = 'SILOMS';

      // Unique ID Generator: SAFE against duplicates
      // ID = COD + GROUP + TIMESTAMP + INDEX (to ensure uniqueness if rows duplicate)
      const uniqueId = `${safeCod}-${groupEnum}-${year}${month}-${index}`;

      normalized.push({
        id: uniqueId,
        date: row.data,
        monthIndex: month,
        year: year,
        cod: safeCod,
        ug: safeUg,
        group: groupEnum,
        siafiValue: siafi || 0,
        silomsValue: siloms || 0,
        difference: finalDiff || 0,
        preponderance,
        // Init optional fields
        previousDifference: 0,
        previousSiafiValue: 0,
        previousSilomsValue: 0,
        previousDate: '',
        delta: 0
      });
    };

    // STRICT GROUP MAPPING
    processGroup(AccountGroup.CONSUMO, row.g1_siafi, row.g1_siloms, row.g1_diff);
    processGroup(AccountGroup.BMP, row.g2_siafi, row.g2_siloms, row.g2_diff);
    processGroup(AccountGroup.INTANGIVEL, row.g3_siafi, row.g3_siloms, row.g3_diff);
  });

  return normalized;
};

// --- DELTA RECALCULATION BASED ON TIME FILTER ---
export const recalculateDeltas = (data: FinancialRecord[], timeFilter: TimeFilter): FinancialRecord[] => {
  // 1. Determine the gap in months based on filter
  let monthGap = 1; // Default MENSAL
  if (timeFilter === 'TRIMESTRAL') monthGap = 3;
  if (timeFilter === 'SEMESTRAL') monthGap = 6;
  if (timeFilter === 'ANUAL') monthGap = 12;

  // Helper for short month names
  const monthNames = ['JAN', 'FEV', 'MAR', 'ABR', 'MAI', 'JUN', 'JUL', 'AGO', 'SET', 'OUT', 'NOV', 'DEZ'];

  return data.map(record => {
    // Calculate target previous date
    let targetMonth = record.monthIndex - monthGap;
    let targetYear = record.year;

    // Handle year rollover (works for any gap size, including 12)
    // Example: Nov 2025 (Index 10). Gap 12. targetMonth = -2. 
    // Loop: -2 < 0 -> targetMonth = 10 (Nov), targetYear = 2024.
    while (targetMonth < 0) {
      targetMonth += 12;
      targetYear -= 1;
    }

    // Find the comparison record (Previous period)
    const prevRecord = data.find(r => 
      r.cod === record.cod && 
      r.group === record.group && 
      r.monthIndex === targetMonth && 
      r.year === targetYear
    );

    const prevDiff = prevRecord ? prevRecord.difference : 0;
    const prevSiafi = prevRecord ? prevRecord.siafiValue : 0;
    const prevSiloms = prevRecord ? prevRecord.silomsValue : 0;

    // Create a meaningful label for "Previous Date"
    let prevDate = 'Sem histórico';

    // Format the target date explicitly (e.g., SET/24)
    const shortYear = targetYear.toString().slice(-2);
    const specificPrevLabel = `${monthNames[targetMonth]}/${shortYear}`;

    if (prevRecord) {
      prevDate = specificPrevLabel; // Force consistent formatting
    } else {
      prevDate = specificPrevLabel;
    }

    // Delta = Current - Previous
    const delta = record.difference - prevDiff;

    return {
      ...record,
      previousDifference: prevDiff,
      previousSiafiValue: prevSiafi,
      previousSilomsValue: prevSiloms,
      previousDate: prevDate,
      delta
    };
  });
};

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
    maximumFractionDigits: 2,
    minimumFractionDigits: 2
  }).format(value || 0);
};

